  threadMemoryModeSetFn = runThreadMemoryModeSetProbe,
  threadRenameFn = runThreadRenameProbe,
  threadRealtimeVoicesFn = runThreadRealtimeVoicesProbe,
  threadRollbackFn = runThreadRollbackProbe,
  threadSafetyLockFn = runThreadSafetyLockProbe,
  accountLoginCancelFn = runAccountLoginCancelProbe,
  accountLoginStartFn = runAccountLoginStartProbe,
  accountCreditsNudgeFn = runAccountCreditsNudgeProbe,
  accountLogoutFn = runAccountLogoutProbe,
  accountResetCreditConsumeFn = runAccountRateLimitResetCreditConsumeProbe,
  threadTranscriptProbeFn = runThreadTranscriptProbe,
  threadTurnItemsProbeFn = runThreadTurnItemsProbe,
  threadTurnsProbeFn = runThreadTurnsProbe,
  threadChangesProbeFn = runThreadChangesProbe,
  turnStartFn = runTurnStartProbe,
  integrationsInventoryFn = runIntegrationsInventoryProbe,
  configBatchWriteFn = runConfigBatchWriteProbe,
  configValueWriteFn = runConfigValueWriteProbe,
  environmentAddFn = runEnvironmentAddProbe,
  experimentalFeatureSetFn = runExperimentalFeatureEnablementSetProbe,
  fsDirectoryFn = runFsDirectoryProbe,
