  approvalAcceptEnabled = process.env.CODEX_APP_PORT_ALLOW_APPROVAL_ACCEPT === "1",
  sessionToken = createSessionToken(),
  preflightRegistry = createPreflightRegistry(),
  turnSessionRegistry = createTurnSessionRegistry({ approvalAuditLog }),
  liveSessionControlLedger = createLiveSessionControlLedger(),
  threadLifecycleActionLedger = createThreadLifecycleActionLedger(),
  accountLoginFlowRegistry = createAccountLoginFlowRegistry(),
  accountLoginLedger = createAccountLoginLedger(),
  accountCreditsNudgeLedger = createAccountCreditsNudgeLedger(),
  accountResetCreditLedger = createAccountResetCreditLedger(),
  accountLogoutLedger = createAccountLogoutLedger(),
  terminalCommandLedger = createTerminalCommandLedger(),
  threadShellCommandLedger = createThreadShellCommandLedger(),
  processSpawnLedger = createProcessSpawnLedger(),
  terminalControlPreflightLedger = createTerminalControlPreflightLedger(),
  terminalControlConfirmationLedger = createTerminalControlConfirmationLedger(),
  backgroundTerminalRegistry = createBackgroundTerminalRegistry(),
  remoteControlClientRegistry = createRemoteControlClientRegistry(),
  fileActionLedger = createFileActionLedger(),
