  const normalized = normalize(allowedPath);
  if (normalized.startsWith("..")) {
    sendJson(response, 400, { ok: false, error: "Invalid path" });
    return;
  }

  const fileUrl = new URL(join(STATIC_ROOT.pathname, normalized), "file://");
