function buildActionPreflightConfirmation(payload, consumedPreflight) {
  const result = {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: payload.workspace,
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
      toolTraffic: false,
    },
    action: {
      type: payload.action?.type,
      method: cleanDisplayText(payload.action?.method, 100),
      execution: "blocked",
      preflightConfirmed: true,
      mutationExecuted: false,
      appServerTouched: false,
      reason: "mutation-pipeline-not-implemented",
    },
    preflight: buildConsumedPreflightSummary(consumedPreflight),
    policy: {
      readOnly: true,
      appServerTraffic: false,
      modelTraffic: false,
      commandExecution: false,
      filesystemWrites: false,
      gitWrites: false,
      toolInvocation: false,
      pluginRead: false,
      pluginContentRead: false,
      pluginShareList: false,
      mutationExecuted: false,
      requiresApprovalPipeline: true,
      requiresLiveSessionManager: Boolean(payload.policy?.requiresLiveSessionManager),
      requiresIntegrationProvenance: Boolean(payload.policy?.requiresIntegrationProvenance),
      requiresWorkspacePathPolicy: Boolean(payload.policy?.requiresWorkspacePathPolicy),
      implemented: false,
    },
  };
  return result;
}

function buildConsumedPreflightSummary(consumedPreflight) {
  const result = {
    tokenConsumed: true,
    tokenReturned: false,
    scope: consumedPreflight.scope,
    rawIntentStored: false,
    rawIntentReturned: false,
    intentHashReturned: false,
    oneTimeUseEnforced: true,
  };
  return result;
}

