function ensureActionAuditLogWritable(actionAuditLog) {
  if (!actionAuditLog || typeof actionAuditLog.ensureWritable !== "function") {
    return false;
  }
  try {
    return Boolean(actionAuditLog.ensureWritable());
  } catch {
    throwRequestError("Action audit log is unavailable", 500);
  }
}

function ensureApprovalAuditLogWritable(approvalAuditLog) {
  if (!approvalAuditLog || typeof approvalAuditLog.ensureWritable !== "function") {
    return false;
  }
  try {
    return Boolean(approvalAuditLog.ensureWritable());
  } catch {
    throwRequestError("Approval decision audit log unavailable", 500);
  }
}

function writeActionAuditLog(actionAuditLog, record) {
  if (!actionAuditLog || typeof actionAuditLog.append !== "function") {
    return false;
  }
  try {
    actionAuditLog.append({
      event: actionAuditEvent(record),
      payload: record,
    });
    return true;
  } catch {
    throwRequestError("Action audit log write failed", 500);
  }
}

