export function createWorkspaceAllowlist({
  cwd = process.cwd(),
  workspaceInputs = [],
  projectRootInputs = [],
} = {}) {
  const baseCwd = resolve(cwd);
  const seen = new Set();
  const labelCounts = new Map();
  const workspaces = [];
  const discoveredProjectInputs = discoverProjectWorkspaces({
    cwd: baseCwd,
    projectRootInputs,
  });

  for (const input of [baseCwd, ...workspaceInputs, ...discoveredProjectInputs]) {
    if (typeof input !== "string" || input.trim().length === 0) {
      continue;
    }
    if (input.includes("\0")) {
      throw new Error("Workspace path contains an invalid NUL byte");
    }

    const absolutePath = resolve(baseCwd, input.trim());
    if (seen.has(absolutePath)) {
      continue;
    }
    seen.add(absolutePath);

    const baseLabel = cleanDisplayText(basename(absolutePath) || "root", 64) ?? "workspace";
    const nextCount = (labelCounts.get(baseLabel) ?? 0) + 1;
    labelCounts.set(baseLabel, nextCount);

    workspaces.push({
      id: workspaces.length === 0 ? "default" : `workspace-${workspaces.length + 1}`,
      label: nextCount === 1 ? baseLabel : `${baseLabel} ${nextCount}`,
      isDefault: workspaces.length === 0,
      cwd: absolutePath,
    });
  }

  if (workspaces.length === 0) {
    throw new Error("At least one workspace must be allowed");
  }

  return workspaces;
}

export function discoverProjectWorkspaces({ cwd = process.cwd(), projectRootInputs = [] } = {}) {
  const baseCwd = resolve(cwd);
  const projectRoots = projectRootInputs.slice(0, MAX_PROJECT_ROOTS);
  const seenProjects = new Set();
  const projects = [];

  for (const input of projectRoots) {
    if (typeof input !== "string" || input.trim().length === 0) {
      continue;
    }
    if (input.includes("\0")) {
      throw new Error("Project root path contains an invalid NUL byte");
    }

    const root = resolve(baseCwd, input.trim());
    const rootInfo = lstatSync(root);
    if (!rootInfo.isDirectory() || rootInfo.isSymbolicLink()) {
      throw new Error("Project root must be a non-symlink directory");
    }

    for (const entry of readdirSync(root, { withFileTypes: true }).slice(0, MAX_PROJECT_ROOT_ENTRIES)) {
      if (projects.length >= MAX_DISCOVERED_PROJECTS) {
        return projects;
      }
      if (!entry.isDirectory() || entry.isSymbolicLink() || entry.name.startsWith(".")) {
        continue;
      }

      const candidate = join(root, entry.name);
      if (!hasGitMetadata(candidate)) {
        continue;
      }

      const realCandidate = realpathSync(candidate);
      if (seenProjects.has(realCandidate)) {
        continue;
      }
      seenProjects.add(realCandidate);
      projects.push(realCandidate);
    }
  }

  return projects;
}

function hasGitMetadata(candidate) {
  try {
    const candidateInfo = lstatSync(candidate);
    if (!candidateInfo.isDirectory() || candidateInfo.isSymbolicLink()) {
      return false;
    }
    const gitInfo = lstatSync(join(candidate, ".git"));
    return !gitInfo.isSymbolicLink() && (gitInfo.isDirectory() || gitInfo.isFile());
  } catch {
    return false;
  }
}

export function publicWorkspaces(workspaces) {
  return workspaces.map((workspace) => ({
    id: workspace.id,
    label: workspace.label,
    isDefault: Boolean(workspace.isDefault),
  }));
}

export function selectWorkspace(workspaces, requestedId) {
  const id = requestedId || "default";
  const workspace = workspaces.find((candidate) => candidate.id === id);
  if (!workspace) {
    const error = new Error("Unknown workspace id");
    error.statusCode = 404;
    throw error;
  }
  return workspace;
}

function requireValue(argv, index, flag) {
  const value = argv[index];
  if (!value || value.startsWith("--")) {
    throw new Error(`${flag} requires a value`);
  }
  return value;
}

function parsePositiveInt(value, flag) {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isSafeInteger(parsed) || parsed <= 0) {
    throw new Error(`${flag} must be a positive integer`);
  }
  return parsed;
}

function securityHeaders(contentType) {
  return {
    "Content-Type": contentType,
    "Cache-Control": "no-store",
    "X-Content-Type-Options": "nosniff",
    "Referrer-Policy": "no-referrer",
    "Content-Security-Policy":
      "default-src 'self'; base-uri 'none'; connect-src 'self'; form-action 'none'; frame-ancestors 'none'; img-src 'self' data:; object-src 'none'; script-src 'self'; style-src 'self'",
    "Permissions-Policy": "camera=(), microphone=(), geolocation=(), payment=()",
  };
}

function sseHeaders() {
  return {
    ...securityHeaders("text/event-stream; charset=utf-8"),
    Connection: "keep-alive",
  };
}

function sendJson(response, statusCode, payload) {
  const safeResponse = applyBrowserPostResponseContract({
    method: response.codexAppPortRequestMethod,
    pathname: response.codexAppPortRequestPath,
    statusCode,
    payload,
  });
  response.writeHead(safeResponse.statusCode, securityHeaders("application/json; charset=utf-8"));
  response.end(`${JSON.stringify(safeResponse.payload, null, 2)}\n`);
}

async function readJsonBody(request) {
  const contentType = request.headers["content-type"] ?? "";
  if (typeof contentType !== "string" || !contentType.startsWith("application/json")) {
    throwRequestError("Content-Type must be application/json", 415);
  }

  let size = 0;
  let raw = "";
  request.setEncoding("utf8");
  for await (const chunk of request) {
    size += Buffer.byteLength(chunk, "utf8");
    if (size > MAX_JSON_BODY_BYTES) {
      throwRequestError("Request body is too large", 413);
    }
    raw += chunk;
  }

  if (raw.trim().length === 0) {
    throwRequestError("Request body is required", 400);
  }

  try {
    return JSON.parse(raw);
  } catch {
    throwRequestError("Request body must be valid JSON", 400);
  }
}

async function readJsonObjectBody(request) {
  const body = await readJsonBody(request);
  if (!body || typeof body !== "object" || Array.isArray(body)) {
    throwRequestError("Request body must be a JSON object", 400);
  }
  return body;
}

async function readStrictJsonObjectBody(request, allowedFields) {
  const contract = routeBodyContract(request, allowedFields);
  const body = await readJsonObjectBody(request);
  rejectUnknownBodyFields(body, contract.allowedFields);
  validateBrowserPostBodyFieldPolicies(body, contract);
  return body;
}

function routeBodyContract(request, allowedFields) {
  if (!Array.isArray(allowedFields)) {
    throwRequestError("Internal POST body contract fields are invalid", 500);
  }
  const pathname = new URL(request.url, `http://${request.headers.host || DEFAULT_HOST}`).pathname;
  const contract = BROWSER_POST_BODY_CONTRACTS[pathname];
  if (!contract) {
    throwRequestError("Internal POST body contract is missing", 500);
  }
  if (contract.enforcedByStrictReader === false) {
    return allowedFields;
  }
  if (!sameStringArray(contract.allowedFields, allowedFields)) {
    throwRequestError("Internal POST body contract mismatch", 500);
  }
  return contract;
}

function rejectUnknownBodyFields(body, allowedFields) {
  const allowed = new Set(allowedFields);
  for (const key of Object.keys(body)) {
    if (!allowed.has(key)) {
      throwRequestError("Request body contains an unsupported field", 400);
    }
  }
}

function validateBrowserPostBodyFieldPolicies(body, contract) {
  for (const [key, value] of Object.entries(body)) {
    const policy = contract.fieldPolicies[key];
    if (!policy) {
      throwRequestError("Internal POST body field policy is missing", 500);
    }
    const type = jsonValueType(value);
    if (!policy.allowedJsonTypes.includes(type)) {
      throwRequestError("Request body field has an unsupported JSON type", 400);
    }
    if (typeof value === "string") {
      if (value.includes("\0")) {
        throwRequestError("Request body field contains unsupported text", 400);
      }
      if (policy.maxChars !== null && value.length > policy.maxChars) {
        throwRequestError("Request body field is too large", 400);
      }
    } else if (
      (type === "object" || type === "array") &&
      policy.maxSerializedChars !== null &&
      JSON.stringify(value).length > policy.maxSerializedChars
    ) {
      throwRequestError("Request body field is too large", 400);
    }
  }
}

function bodyFields(...fields) {
  return Object.freeze([...fields]);
}

function bodyFieldPolicy(allowedJsonTypes, metadata = {}) {
  return Object.freeze({
    allowedJsonTypes: Object.freeze([...allowedJsonTypes]),
    maxChars: null,
    maxSerializedChars: null,
    returnedRawValue: false,
    sensitivity: "unspecified",
    ...metadata,
  });
}

function browserPostResponseContract({
  kind,
  mayReturnPreflightToken = false,
  allowedTopLevelKeys = null,
  nestedKeySchemas = null,
} = {}) {
  const cleanKind = cleanContractLabel(kind);
  const routeKeys = Array.isArray(allowedTopLevelKeys)
    ? Object.freeze([...allowedTopLevelKeys])
    : responseTopLevelKeysForKind(cleanKind);
  const routeNestedKeySchemas = nestedKeySchemas ?? Object.freeze({});
  return Object.freeze({
    kind: cleanKind,
    validatesResponses: true,
    rejectsUnexpectedTopLevelKeys: true,
    rejectsForbiddenNestedKeys: true,
    rejectsUnexpectedSchemaNestedKeys: true,
    usesRouteSpecificTopLevelKeys: Array.isArray(allowedTopLevelKeys),
    usesRouteSpecificNestedKeySchemas: Object.keys(routeNestedKeySchemas).length > 0,
    allowedTopLevelKeys: routeKeys,
    nestedKeySchemas: routeNestedKeySchemas,
    rejectsSecretPatterns: true,
    rejectsAbsolutePaths: true,
    rejectsUnsafeTokenStrings: true,
    rejectsTruthySensitiveReturnFlags: true,
    forbiddenTruthyFlagKeys: BROWSER_POST_RESPONSE_FORBIDDEN_TRUTHY_FLAG_KEYS,
    forbiddenNestedKeys: BROWSER_POST_RESPONSE_FORBIDDEN_NESTED_KEYS,
    allowedPreflightTokenPaths: Object.freeze(
      mayReturnPreflightToken ? ["preflight.token"] : [],
    ),
  });
}

export function applyBrowserPostResponseContract({ method, pathname, statusCode, payload }) {
  const contract =
    method === "POST" && typeof pathname === "string"
      ? BROWSER_POST_RESPONSE_CONTRACTS[pathname]
      : null;
  if (!contract) {
    return { statusCode, payload };
  }
  const violation = browserPostResponseViolation(payload, contract);
  if (!violation) {
    return { statusCode, payload };
  }
  return {
    statusCode: 500,
    payload: {
      ok: false,
      error: "Browser POST response contract violation",
    },
  };
}

function bodyContract(allowedFields, metadata = {}) {
  const fields = Object.freeze([...allowedFields]);
  const fieldPolicies = {};
  for (const field of fields) {
    const policy = BROWSER_POST_FIELD_POLICIES[field];
    if (!policy) {
      throw new Error(`Missing browser POST field policy for ${field}`);
    }
    fieldPolicies[field] = policy;
  }
  return Object.freeze({
    allowedFields: fields,
    allowedFieldCount: fields.length,
    fieldPolicies: Object.freeze(fieldPolicies),
    fieldPolicyCount: Object.keys(fieldPolicies).length,
    requiresApiToken: true,
    rejectsUnknownFields: true,
    enforcedByStrictReader: true,
    requiresPreflightToken: false,
    ...metadata,
  });
}

function browserPostResponseViolation(payload, contract) {
  const topLevelViolation = browserPostTopLevelKeyViolation(payload, contract);
  if (topLevelViolation) {
    return topLevelViolation;
  }
  const stack = [{ value: payload, path: [] }];
  while (stack.length > 0) {
    const { value, path } = stack.pop();
    if (unsafeBrowserPostResponseTruthyFlag(value, path, contract)) {
      return "truthy-sensitive-return-flag";
    }
    if (typeof value === "string") {
      if (value.includes("\0")) {
        return "nul-text";
      }
      if (unsafeBrowserPostResponseToken(value, path, contract)) {
        return "unsafe-token";
      }
      if (SECRET_RESPONSE_PATTERN.test(value)) {
        return "secret";
      }
      if (ABSOLUTE_PATH_RESPONSE_PATTERN.test(value)) {
        return "absolute-path";
      }
      continue;
    }
    if (!value || typeof value !== "object") {
      continue;
    }
    if (Array.isArray(value)) {
      for (let index = 0; index < value.length; index += 1) {
        stack.push({ value: value[index], path: [...path, String(index)] });
      }
      continue;
    }
    if (browserPostNestedObjectKeyViolation(value, path, contract)) {
      return "unexpected-nested-key";
    }
    for (const [key, child] of Object.entries(value)) {
      const childPath = [...path, key];
      if (unsafeBrowserPostResponseNestedKey(childPath, contract)) {
        return "forbidden-nested-key";
      }
      stack.push({ value: child, path: childPath });
    }
  }
  return null;
}

function browserPostTopLevelKeyViolation(payload, contract) {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    return null;
  }
  const allowed = new Set(contract.allowedTopLevelKeys);
  for (const key of Object.keys(payload)) {
    if (!allowed.has(key)) {
      return "unexpected-top-level-key";
    }
  }
  return null;
}

const PREFLIGHT_TOKEN_RESPONSE_PATTERN = /\bpreflight-[A-Za-z0-9_-]{16,128}\b/;
const SECRET_RESPONSE_PATTERN =
  /\b(?:sk-[A-Za-z0-9_-]{8,}|gh[pousr]_[A-Za-z0-9_]{8,}|xox[baprs]-[A-Za-z0-9-]{8,}|AKIA[0-9A-Z]{16})\b/;
const ABSOLUTE_PATH_RESPONSE_PATTERN =
  /(^|[\s"'=])(?:~\/|\/(?:home|tmp|var|etc|usr|opt|root|run|mnt|media|private|Users)\/)[^\s"',}]*/;

function unsafeBrowserPostResponseToken(value, path, contract) {
  const dottedPath = path.join(".");
  if (PREFLIGHT_TOKEN_RESPONSE_PATTERN.test(value)) {
    return !contract.allowedPreflightTokenPaths.includes(dottedPath);
  }
  const key = path.at(-1) ?? "";
  return /token/i.test(key) && value.trim().length > 0;
}

function unsafeBrowserPostResponseTruthyFlag(value, path, contract) {
  const key = path.at(-1) ?? "";
  return contract.forbiddenTruthyFlagKeys.includes(key) && Boolean(value);
}

function unsafeBrowserPostResponseNestedKey(path, contract) {
  const key = path.at(-1) ?? "";
  if (!contract.forbiddenNestedKeys.includes(key)) {
    return false;
  }
  const dottedPath = path.join(".");
  return !contract.allowedPreflightTokenPaths.includes(dottedPath);
}

function browserPostNestedObjectKeyViolation(value, path, contract) {
  const allowedKeys = browserPostNestedSchemaKeysForPath(path, contract);
  if (!allowedKeys) {
    return false;
  }
  const allowed = new Set(allowedKeys);
  return Object.keys(value).some((key) => !allowed.has(key));
}

function browserPostNestedSchemaKeysForPath(path, contract) {
  const dottedPath = path.join(".");
  const exact = contract.nestedKeySchemas[dottedPath];
  if (exact || !path.some(isArrayIndexPathSegment)) {
    return exact;
  }
  const wildcardPath = path.map((segment) =>
    isArrayIndexPathSegment(segment) ? "*" : segment,
  ).join(".");
  return contract.nestedKeySchemas[wildcardPath];
}

function isArrayIndexPathSegment(value) {
  return /^(?:0|[1-9]\d*)$/.test(value);
}

function cleanContractLabel(value) {
  return typeof value === "string" && /^[a-z0-9-]+$/.test(value) ? value : "unknown";
}

function responseTopLevelKeys(...keys) {
  return Object.freeze([...new Set(keys)]);
}

function routeResponseTopLevelKeys(...keys) {
  return responseTopLevelKeys("ok", "error", "generatedAt", ...keys);
}

function routeSpecificResponseTopLevelKeys(path, kind) {
  return BROWSER_POST_RESPONSE_ROUTE_TOP_LEVEL_KEYS[path] ?? responseTopLevelKeysForKind(kind);
}

function routeSpecificResponseNestedKeySchemas(path) {
  return BROWSER_POST_RESPONSE_NESTED_KEY_SCHEMAS[path] ?? Object.freeze({});
}

function responseNestedKeySchemas(schema) {
  return Object.freeze(
    Object.fromEntries(
      Object.entries(schema).map(([path, keys]) => [path, Object.freeze([...keys])]),
    ),
  );
}

function responseTopLevelKeysForKind(kind) {
  switch (kind) {
    case "preflight":
      return BROWSER_POST_RESPONSE_TOP_LEVEL_KEYS.preflight;
    case "mutation":
      return BROWSER_POST_RESPONSE_TOP_LEVEL_KEYS.mutation;
    case "approval-decision":
      return BROWSER_POST_RESPONSE_TOP_LEVEL_KEYS.approvalDecision;
    case "preflight-confirmation":
      return BROWSER_POST_RESPONSE_TOP_LEVEL_KEYS.preflightConfirmation;
    default:
      return BROWSER_POST_RESPONSE_TOP_LEVEL_KEYS.common;
  }
}

function jsonValueType(value) {
  if (value === null) {
    return "null";
  }
  if (Array.isArray(value)) {
    return "array";
  }
  return typeof value;
}

function sameStringArray(left, right) {
  if (!Array.isArray(left) || !Array.isArray(right) || left.length !== right.length) {
    return false;
  }
  return left.every((value, index) => value === right[index]);
}

function sendSse(response, eventName, payload) {
  if (response.writableEnded) {
    return;
  }
  response.write(`event: ${eventName}\n`);
  response.write(`data: ${JSON.stringify(payload)}\n\n`);
}

function hasValidApiToken(request, sessionToken) {
  const candidate = request.headers[API_TOKEN_HEADER];
  if (typeof candidate !== "string" || typeof sessionToken !== "string") {
    return false;
  }
  const candidateBuffer = Buffer.from(candidate, "utf8");
  const sessionBuffer = Buffer.from(sessionToken, "utf8");
  if (candidateBuffer.length !== sessionBuffer.length) {
    return false;
  }
  return timingSafeEqual(candidateBuffer, sessionBuffer);
}

function injectSessionToken(html, sessionToken) {
  if (!html.includes(SESSION_TOKEN_PLACEHOLDER)) {
    throw new Error("index.html is missing the session token placeholder");
  }
  return html.replaceAll(SESSION_TOKEN_PLACEHOLDER, escapeAttribute(sessionToken));
}

function escapeAttribute(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll('"', "&quot;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;");
}

