function buildTurnSessionLifecycle(sessions, { options = {}, managedSession = null } = {}) {
  const items = Array.isArray(sessions) ? sessions : [];
  const sessionCount = items.length;
  const pendingApprovalCount = items.reduce((count, session) => {
    const requests = Array.isArray(session?.approvals?.requests) ? session.approvals.requests : [];
    return count + requests.filter((request) => !request.browserDecision).length;
  }, 0);
  const decidedApprovalCount = items.reduce((count, session) => {
    const requests = Array.isArray(session?.approvals?.requests) ? session.approvals.requests : [];
    return count + requests.filter((request) => Boolean(request.browserDecision)).length;
  }, 0);
  const eventCount = items.reduce(
    (count, session) => count + safeCount(session?.events?.returnedEventCount),
    0,
  );
  const pendingApprovalSessionCount = items.filter((session) => {
    const requests = Array.isArray(session?.approvals?.requests) ? session.approvals.requests : [];
    return requests.some((request) => !request.browserDecision);
  }).length;
  const decidedApprovalSessionCount = items.filter((session) => {
    const requests = Array.isArray(session?.approvals?.requests) ? session.approvals.requests : [];
    return requests.some((request) => Boolean(request.browserDecision));
  }).length;
  const eventSessionCount = items.filter(
    (session) => safeCount(session?.events?.returnedEventCount) > 0,
  ).length;
  const modelTrafficSessionCount = items.filter((session) => session?.action?.modelTraffic).length;
  const latestSession = items[0] ?? null;
  const latestEvents = Array.isArray(latestSession?.events?.items)
    ? latestSession.events.items
    : [];
  const latestEvent = latestEvents.at(-1) ?? null;
  const turnStartEnabled = Boolean(options.turnStartEnabled);
  const approvalForwardingEnabled = isApprovalForwardingGateEnabled(options);
  const approvalAcceptEnabled = isApprovalAcceptGateEnabled(options);
  const managedSessionLifecycle = buildManagedTurnSessionLifecycle(managedSession, { options });
  const approvalPolicy = buildTurnSessionApprovalPolicy({
    options,
    managedSessionLifecycle,
    pendingApprovalCount,
    decidedApprovalCount,
    pendingApprovalSessionCount,
    decidedApprovalSessionCount,
  });
  const turnSessionOperations = summarizeTurnSessionOperations({
    options,
    sessionCount,
    pendingApprovalCount,
    decidedApprovalCount,
    eventSessionCount,
    modelTrafficSessionCount,
    managedSessionLifecycle,
    approvalPolicy,
  });
  const turnSessionManagement = summarizeTurnSessionManagement({
    latestSession,
    managedSessionLifecycle,
    approvalPolicy,
    turnSessionOperations,
  });
  const turnSessionReadiness = summarizeTurnSessionReadiness({
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
  });
  const turnSessionRoutingContract = summarizeTurnSessionRoutingContract({
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
    turnSessionReadiness,
  });
  const turnSessionWorkflowContract = summarizeTurnSessionWorkflowContract({
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
    turnSessionReadiness,
    turnSessionRoutingContract,
  });
  const turnSessionSafetyContract = summarizeTurnSessionSafetyContract({
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
    turnSessionReadiness,
    turnSessionRoutingContract,
  });
  const turnSessionAuditContract = summarizeTurnSessionAuditContract({
    options,
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
    turnSessionReadiness,
    turnSessionRoutingContract,
    eventCount,
  });
  return {
    state:
      sessionCount === 0
        ? turnStartEnabled
          ? "idle"
          : "blocked"
        : pendingApprovalCount > 0
          ? "pending-approval"
          : "history-only",
    sessionCount,
    pendingApprovalCount,
    decidedApprovalCount,
    pendingApprovalSessionCount,
    decidedApprovalSessionCount,
    eventSessionCount,
    modelTrafficSessionCount,
    returnedEventCount: eventCount,
    latestStatus: cleanDisplayText(latestSession?.status, 40),
    latest: latestSession
      ? {
          recordedAt: cleanDisplayText(latestSession.recordedAt, 40),
          status: cleanDisplayText(latestSession.status, 40),
          threadIdSuffix: cleanDisplayText(latestSession.target?.threadIdSuffix, 16),
          turnIdSuffix: cleanDisplayText(latestSession.target?.turnIdSuffix, 16),
          eventMethod: cleanDisplayText(latestEvent?.method, 100),
          eventStatus: cleanDisplayText(latestEvent?.status, 40),
          promptCharCount: safeCount(latestSession.prompt?.charCount),
          eventTextReturned: false,
          promptTextReturned: false,
          fullIdsReturned: false,
          pathsReturned: false,
          rawEventReturned: false,
        }
      : null,
    turnStartPreflightAvailable: true,
    turnStartEnabled,
    sessionManagerEnabled: Boolean(options.sessionManagerEnabled),
    managedSession: managedSessionLifecycle,
    approvalPolicy,
    turnSessionOperations,
    turnSessionManagement,
    turnSessionReadiness,
    turnSessionRoutingContract,
    turnSessionWorkflowContract,
    turnSessionSafetyContract,
    turnSessionAuditContract,
    approvalForwardingEnabled,
    approvalAcceptEnabled,
    sessionWideApprovalDecisionsAccepted: false,
    lifecycleDetailReturned: true,
    modelTrafficGateEnabled: turnStartEnabled,
    fullIdsReturned: false,
    promptsReturned: false,
    pathsReturned: false,
    decisionTokensReturned: false,
    rawEventsReturned: false,
  };
}

