function summarizeTurnSessionOperations({
  options = {},
  sessionCount = 0,
  pendingApprovalCount = 0,
  decidedApprovalCount = 0,
  eventSessionCount = 0,
  modelTrafficSessionCount = 0,
  managedSessionLifecycle = null,
  approvalPolicy = null,
} = {}) {
  const turnStartEnabled = Boolean(options.turnStartEnabled);
  const threadStartEnabled = Boolean(options.threadStartEnabled);
  const threadArchiveEnabled = Boolean(options.threadArchiveEnabled);
  const threadCompactEnabled = Boolean(options.threadCompactEnabled && options.sessionManagerEnabled);
  const sessionManagerEnabled = Boolean(options.sessionManagerEnabled);
  const persistentSessionManager = Boolean(managedSessionLifecycle?.persistentClient);
  const enabledThreadLifecycleOperationCount = [
    threadStartEnabled,
    threadArchiveEnabled,
    threadCompactEnabled,
  ].filter(Boolean).length;
  const enabledTurnOperationCount = turnStartEnabled ? 1 : 0;
  const enabledOperationCount =
    enabledThreadLifecycleOperationCount + enabledTurnOperationCount;
  return {
    returned: true,
    state: turnStartEnabled
      ? sessionManagerEnabled
        ? "managed"
        : "local"
      : sessionCount > 0
        ? "history-only"
        : "blocked",
    sessionCount: safeCount(sessionCount),
    pendingApprovalCount: safeCount(pendingApprovalCount),
    decidedApprovalCount: safeCount(decidedApprovalCount),
    eventSessionCount: safeCount(eventSessionCount),
    modelTrafficSessionCount: safeCount(modelTrafficSessionCount),
    enabledOperationCount,
    enabledThreadLifecycleOperationCount,
    enabledTurnOperationCount,
    threadStartEnabled,
    threadArchiveEnabled,
    threadCompactEnabled,
    turnStartEnabled,
    turnStartPreflightAvailable: true,
    turnStartRoute: sessionManagerEnabled ? "session-manager" : "local-probe",
    modelTrafficGateEnabled: turnStartEnabled,
    sessionManagerEnabled,
    persistentSessionManager,
    managerClientStarted: Boolean(managedSessionLifecycle?.clientStarted),
    managerPendingApprovalCount: safeCount(managedSessionLifecycle?.pendingApprovalCount),
    managerResolvedApprovalCount: safeCount(managedSessionLifecycle?.resolvedApprovalCount),
    managerNotificationCount: safeCount(managedSessionLifecycle?.notificationCount),
    approvalForwardingEnabled: isApprovalForwardingGateEnabled(options),
    approvalAcceptEnabled: isApprovalAcceptGateEnabled(options),
    requestScopedApprovalOnly: Boolean(approvalPolicy?.requestScopedOnly),
    sessionWideApprovalDecisionsAccepted: false,
    preflightRequiredForModelTraffic: true,
    preflightTokensReturned: false,
    promptsReturned: false,
    fullIdsReturned: false,
    pathsReturned: false,
    decisionTokensReturned: false,
    rawApprovalDetailsReturned: false,
    rawEventsReturned: false,
    appServerPayloadReturned: false,
  };
}

