function recordApprovalDecisionFromBody(
  body,
  { workspace, options, approvalAcceptEnabled = false } = {},
) {
  const useApprovalForwarder =
    isApprovalForwardingGateEnabled(options) &&
    typeof body.session === "string" &&
    body.session.startsWith("managed-");
  return useApprovalForwarder
    ? options.sessionManager?.recordApprovalDecision({
        workspace,
        sessionId: body.session,
        requestKey: body.request,
        decision: body.decision,
        decisionToken: body.decisionToken,
        allowApprove: approvalAcceptEnabled,
      })
    : options.turnSessionRegistry?.recordApprovalDecision({
        workspaceId: workspace.id,
        sessionId: body.session,
        requestKey: body.request,
        decision: body.decision,
        decisionToken: body.decisionToken,
      });
}

function validateApprovalDecisionBatch(body) {
  for (const field of ["session", "request", "decision", "decisionToken"]) {
    if (Object.hasOwn(body, field)) {
      throwRequestError("Approval decision batch must not mix single-decision fields", 400);
    }
  }
  if (!Array.isArray(body.decisions)) {
    throwRequestError("Approval decision batch must be an array", 400);
  }
  if (body.decisions.length === 0) {
    throwRequestError("Approval decision batch must include at least one decision", 400);
  }
  if (body.decisions.length > MAX_APPROVAL_DECISION_BATCH) {
    throwRequestError("Approval decision batch is too large", 413);
  }

  const allowedFields = new Set(["session", "request", "decision", "decisionToken"]);
  const seenRequests = new Set();
  return body.decisions.map((entry) => {
    if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
      throwRequestError("Approval decision batch entry is invalid", 400);
    }
    for (const field of Object.keys(entry)) {
      if (!allowedFields.has(field)) {
        throwRequestError("Approval decision batch entry contains an unsupported field", 400);
      }
    }
    const decision = {
      session: validateApprovalDecisionBatchField(entry.session, "session"),
      request: validateApprovalDecisionBatchField(entry.request, "request"),
      decision: validateApprovalDecisionBatchField(entry.decision, "decision"),
      decisionToken: validateApprovalDecisionBatchField(entry.decisionToken, "decisionToken"),
    };
    const requestKey = `${decision.session}\0${decision.request}`;
    if (seenRequests.has(requestKey)) {
      throwRequestError("Approval decision batch contains a duplicate request", 409);
    }
    seenRequests.add(requestKey);
    return decision;
  });
}

function validateApprovalDecisionBatchAgainstPending(
  batch,
  { workspace, options, approvalAcceptEnabled = false } = {},
) {
  const pendingApprovals = [
    ...(options.turnSessionRegistry?.listApprovalRequests({ workspaceId: workspace.id }) ?? []),
    ...(isApprovalForwardingGateEnabled(options)
      ? options.sessionManager?.listApprovalRequests({
          workspace,
          includeDetails: false,
        }) ?? []
      : []),
  ];
  const pendingByRequest = new Map();
  for (const approval of pendingApprovals) {
    const key = approvalDecisionBatchRequestKey(approval?.sessionId, approval?.request?.requestKey);
    if (key) {
      pendingByRequest.set(key, approval);
    }
  }

  for (const decision of batch) {
    const pending = pendingByRequest.get(
      approvalDecisionBatchRequestKey(decision.session, decision.request),
    );
    if (!pending) {
      throwRequestError("Unknown pending approval request", 404);
    }
    if (pending.browserDecision) {
      throwRequestError("Approval decision already recorded", 409);
    }
    if (!approvalDecisionTokensEqual(pending.request?.decisionToken, decision.decisionToken)) {
      throwRequestError("Invalid approval decision token", 403);
    }
    validatePendingApprovalBatchDecision(pending, decision, { approvalAcceptEnabled });
    validatePendingApprovalAuditReplay(pending, options.approvalAuditLog);
  }
}

function validatePendingApprovalBatchDecision(
  pending,
  decision,
  { approvalAcceptEnabled = false } = {},
) {
  const safeDenyDecisions = new Set(
    Array.isArray(pending.request?.safeDenyDecisions) ? pending.request.safeDenyDecisions : [],
  );
  const safeApproveDecisions = new Set(
    approvalAcceptEnabled && Array.isArray(pending.request?.safeApproveDecisions)
      ? pending.request.safeApproveDecisions
      : [],
  );
  if (!safeDenyDecisions.has(decision.decision) && !safeApproveDecisions.has(decision.decision)) {
    throwRequestError("Unsupported approval decision", 400);
  }
}

function validatePendingApprovalAuditReplay(pending, approvalAuditLog) {
  if (!approvalAuditLog || typeof approvalAuditLog.hasRecordedDecision !== "function") {
    return;
  }
  try {
    if (
      approvalAuditLog.hasRecordedDecision({
        event: "approval-decision-recorded",
        sessionId: pending.sessionId,
        workspace: pending.workspace,
        target: pending.target,
        request: pending.request,
      })
    ) {
      throwRequestError("Approval decision already recorded in audit log", 409);
    }
  } catch (error) {
    if (error?.statusCode) {
      throw error;
    }
    throwRequestError("Approval decision audit log unavailable", 500);
  }
}

function approvalDecisionBatchRequestKey(sessionId, requestKey) {
  if (typeof sessionId !== "string" || typeof requestKey !== "string") {
    return null;
  }
  return `${sessionId}\0${requestKey}`;
}

function approvalDecisionTokensEqual(expected, actual) {
  if (typeof expected !== "string" || typeof actual !== "string") {
    return false;
  }
  const expectedBuffer = Buffer.from(expected, "utf8");
  const actualBuffer = Buffer.from(actual, "utf8");
  if (expectedBuffer.length !== actualBuffer.length) {
    return false;
  }
  return timingSafeEqual(expectedBuffer, actualBuffer);
}

function validateApprovalDecisionBatchField(value, field) {
  const policy = BROWSER_POST_FIELD_POLICIES[field];
  if (typeof value !== "string") {
    throwRequestError("Approval decision batch entry is invalid", field === "decisionToken" ? 403 : 400);
  }
  if (value.includes("\0")) {
    throwRequestError("Approval decision batch entry contains unsupported text", 400);
  }
  if (policy?.maxChars !== null && value.length > policy.maxChars) {
    throwRequestError("Approval decision batch entry is too large", 400);
  }
  return value;
}

export function sanitizeGitWorktreePayload(payload, { workspace = null } = {}) {
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: workspace ? publicWorkspaces([workspace])[0] : null,
    git: sanitizeGitWorktree(payload?.git),
  };
}

export function buildGitBranchPreflight(body, { workspace, git, branchSwitchEnabled = false }) {
  const summary = sanitizeGitWorktree(git);
  if (!summary.isRepository || summary.gitMetadataType !== "directory") {
    throwRequestError("Git repository is not available for branch preflight", 409);
  }

  const targetName = validateGitBranchTarget(body?.branch);
  const target = summary.branches.find((branch) => branch.name === targetName);
  if (!target) {
    throwRequestError("Branch target was not found in read-only inventory", 404);
  }

  const changedCount =
    summary.modifiedTrackedCount +
    summary.missingTrackedCount +
    summary.untrackedTopLevelCount;
  const alreadyCurrent = target.current === true;
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "git-branch-switch",
      execution: "blocked",
      wouldSwitchBranch: false,
      commandExecution: false,
      filesystemWrites: false,
      appServerTouched: false,
      reason: alreadyCurrent ? "branch-already-current" : "git-mutation-not-implemented",
    },
    target: {
      branch: target.name,
      current: alreadyCurrent,
      commitShort: target.commitShort,
    },
    status: {
      statusAvailable: summary.statusAvailable,
      changedCount,
      modifiedTrackedCount: summary.modifiedTrackedCount,
      missingTrackedCount: summary.missingTrackedCount,
      untrackedTopLevelCount: summary.untrackedTopLevelCount,
      statusTruncated: summary.statusTruncated,
    },
    safety: summary.branchSwitchSafety,
    policy: {
      readOnly: true,
      gitSubprocess: false,
      filesystemWrites: false,
      branchSwitchExecuted: false,
      requiresExplicitConfirmation: true,
      requiresCleanWorktreePolicy: true,
      requiresHookFilterAttributeAudit: true,
      executionRouteImplemented: true,
      executionGateEnabled: Boolean(branchSwitchEnabled),
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

