export function buildGitBranchDeletePreflight(body, { workspace, git, branchDeleteEnabled = false }) {
  const summary = sanitizeGitWorktree(git);
  if (!summary.isRepository || summary.gitMetadataType !== "directory") {
    throwRequestError("Git repository is not available for branch deletion", 409);
  }

  const targetName = validateGitBranchTarget(body?.branch);
  const target = summary.branches.find((branch) => branch.name === targetName);
  if (!target) {
    throwRequestError("Branch target was not found in read-only inventory", 404);
  }
  if (target.current) {
    throwRequestError("Current branch cannot be deleted", 409);
  }
  if (summary.linkedWorktrees.some((worktree) => worktree.branch === targetName)) {
    throwRequestError("Branch is checked out by a linked worktree", 409);
  }

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "git-branch-delete",
      execution: "blocked",
      wouldDeleteBranch: false,
      refDelete: false,
      gitSubprocess: false,
      filesystemWrites: false,
      appServerTouched: false,
      reason: "git-branch-delete-requires-opt-in",
    },
    target: {
      branch: target.name,
      current: false,
      commitShort: target.commitShort,
    },
    status: {
      localBranchCount: summary.localBranchCount,
      returnedBranchCount: summary.returnedBranchCount,
    },
    policy: {
      readOnly: true,
      directRefDelete: false,
      gitSubprocess: false,
      filesystemWrites: false,
      branchDeleted: false,
      requiresExplicitConfirmation: true,
      executionRouteImplemented: true,
      executionGateEnabled: Boolean(branchDeleteEnabled),
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

