export function buildGitWorktreeActionPreflight(
  body,
  { workspace, git, gitWorktreeActionEnabled = false },
) {
  const summary = sanitizeGitWorktree(git);
  if (!summary.isRepository || summary.gitMetadataType !== "directory") {
    throwRequestError("Git repository is not available for worktree preflight", 409);
  }

  const worktreeAction = validateGitWorktreeAction(body?.action);
  const target = validateGitWorktreePath(body?.path);
  let branch = null;
  if (worktreeAction === "create") {
    const branchName = validateGitBranchTarget(body?.branch);
    const targetBranch = summary.branches.find((candidate) => candidate.name === branchName);
    if (!targetBranch) {
      throwRequestError("Git worktree branch was not found in read-only inventory", 404);
    }
    branch = {
      branch: targetBranch.name,
      current: targetBranch.current,
      commitShort: targetBranch.commitShort,
    };
  } else if (body?.branch != null) {
    throwRequestError("Git worktree branch is invalid for this action", 400);
  }

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "git-worktree",
      worktreeAction,
      execution: "blocked",
      wouldCreateWorktree: false,
      wouldRemoveWorktree: false,
      gitSubprocess: false,
      filesystemWrites: false,
      appServerTouched: false,
      reason: "git-worktree-action-requires-opt-in",
    },
    target: {
      basename: target.basename,
      depth: target.depth,
      pathReturned: false,
    },
    branch,
    status: {
      localBranchCount: summary.localBranchCount,
      linkedWorktreeCount: summary.linkedWorktreeCount,
      returnedLinkedWorktreeCount: summary.returnedLinkedWorktreeCount,
    },
    safety: summary.branchSwitchSafety,
    policy: {
      readOnly: true,
      gitSubprocess: false,
      filesystemWrites: false,
      worktreeCreated: false,
      worktreeRemoved: false,
      requiresExplicitConfirmation: true,
      requiresWorkspacePathPolicy: true,
      requiresHookPolicy: true,
      requiresApprovalPipeline: true,
      executionRouteImplemented: true,
      executionGateEnabled: Boolean(gitWorktreeActionEnabled),
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

