export function buildTerminalCommandPreflight(
  body,
  { workspace, terminalCommandEnabled = false, terminalCommandAllowlist = [] } = {},
) {
  const command = validateTerminalCommand(body?.command);
  const argv = parseTerminalCommandArgv(command);
  const allowlist = sanitizeTerminalCommandAllowlist(terminalCommandAllowlist);
  const executableAllowed = Boolean(argv && allowlist.includes(argv[0]));
  const executionGateEnabled = Boolean(terminalCommandEnabled && executableAllowed);
  const commandSummary = {
    hasContent: true,
    charCount: command.length,
    lineCount: command.split(/\r\n|\r|\n/).length,
    argumentCount: argv?.length ?? 0,
    argvSupported: Boolean(argv),
    executableAllowed,
    textReturned: false,
    argvReturned: false,
    executableReturned: false,
  };
  if (argv) {
    Object.defineProperty(commandSummary, TERMINAL_COMMAND_ARGV, {
      value: argv,
      enumerable: false,
    });
  }
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "terminal-command-preflight",
      method: "command/exec",
      execution: "blocked",
      wouldExecuteCommand: false,
      commandExecution: false,
      terminalSessionCreated: false,
      appServerTouched: false,
      reason: executionGateEnabled
        ? "terminal-command-execution-requires-confirmation"
        : "terminal-command-requires-opt-in-allowlist",
    },
    command: commandSummary,
    policy: {
      readOnly: true,
      appServerTraffic: false,
      commandExecution: false,
      terminalWrite: false,
      terminalResize: false,
      terminalTerminate: false,
      filesystemWrites: false,
      requiresApprovalPipeline: true,
      requiresLiveSessionManager: true,
      requiresExplicitEnablement: true,
      requiresCommandAllowlist: true,
      executionRouteImplemented: true,
      executionGateEnabled,
      allowedCommandCount: allowlist.length,
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

