export function buildFileActionPreflight(body, { workspace, fileActionEnabled = false }) {
  const action = validateFileActionType(body?.action);
  const target = validateFileActionPath(action === "copy" ? body?.targetPath : body?.path, {
    label: "Target path",
  });
  const source = action === "copy"
    ? validateFileActionPath(body?.sourcePath, { label: "Source path" })
    : null;
  const content = action === "writeFile" ? validateFileActionContent(body?.content) : null;
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "file-action-preflight",
      fileAction: action,
      method: fileActionMethod(action),
      execution: "blocked",
      wouldMutateFilesystem: false,
      filesystemWrites: false,
      appServerTouched: false,
      reason: "filesystem-action-requires-opt-in",
    },
    target: {
      basename: target.basename,
      depth: target.depth,
      pathReturned: false,
    },
    source: source
      ? {
          basename: source.basename,
          depth: source.depth,
          pathReturned: false,
        }
      : null,
    content: {
      present: content !== null,
      charCount: content?.length ?? 0,
      lineCount: content ? content.split(/\r\n|\r|\n/).length : 0,
      textReturned: false,
    },
    policy: {
      readOnly: true,
      appServerTraffic: false,
      filesystemWrites: false,
      fileContentsReturned: false,
      fullPathsReturned: false,
      requiresApprovalPipeline: true,
      requiresWorkspacePathPolicy: true,
      executionRouteImplemented: true,
      executionGateEnabled: Boolean(fileActionEnabled),
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

