function summarizeMcpResourceReadResult(value) {
  const contents = Array.isArray(value?.contents) ? value.contents : [];
  const source = contents.length > 0 ? { contents } : value ?? {};
  const summary = {
    contentCount: safeCount(source.contentCount),
    textContentCount: safeCount(source.textContentCount),
    blobContentCount: safeCount(source.blobContentCount),
    mimeTypeCount: safeCount(source.mimeTypeCount),
    textCharCount: safeCount(source.textCharCount),
    blobCharCount: safeCount(source.blobCharCount),
    maxContentCharCount: safeCount(source.maxContentCharCount),
  };
  if (contents.length === 0) {
    return summary;
  }
  summary.contentCount = contents.length;
  summary.textContentCount = 0;
  summary.blobContentCount = 0;
  summary.mimeTypeCount = 0;
  summary.textCharCount = 0;
  summary.blobCharCount = 0;
  summary.maxContentCharCount = 0;
  for (const content of contents) {
    if (typeof content?.text === "string") {
      summary.textContentCount += 1;
      summary.textCharCount += content.text.length;
      summary.maxContentCharCount = Math.max(summary.maxContentCharCount, content.text.length);
    }
    if (typeof content?.blob === "string") {
      summary.blobContentCount += 1;
      summary.blobCharCount += content.blob.length;
      summary.maxContentCharCount = Math.max(summary.maxContentCharCount, content.blob.length);
    }
    if (typeof content?.mimeType === "string" && content.mimeType.length > 0) {
      summary.mimeTypeCount += 1;
    }
  }
  return summary;
}

