function summarizePluginContentReadResult(value) {
  const method = cleanDisplayText(value?.method, 100);
  if (typeof value?.contents === "string" || Object.hasOwn(value ?? {}, "contents")) {
    const contents = typeof value.contents === "string" ? value.contents : "";
    return {
      method: "plugin/skill/read",
      skillContentPresent: contents.length > 0,
      contentCharCount: contents.length,
      contentLineCount: contents.length > 0 ? contents.split(/\r\n|\r|\n/).length : 0,
      itemCount: 0,
      shareUrlCount: 0,
      localPathCount: 0,
      installedCount: 0,
      enabledCount: 0,
    };
  }
  if (Array.isArray(value?.data)) {
    let shareUrlCount = 0;
    let localPathCount = 0;
    let installedCount = 0;
    let enabledCount = 0;
    for (const item of value.data) {
      if (typeof item?.shareUrl === "string" && item.shareUrl.length > 0) {
        shareUrlCount += 1;
      }
      if (typeof item?.localPluginPath === "string" && item.localPluginPath.length > 0) {
        localPathCount += 1;
      }
      if (item?.plugin?.installed === true) {
        installedCount += 1;
      }
      if (item?.plugin?.enabled === true) {
        enabledCount += 1;
      }
    }
    return {
      method: "plugin/share/list",
      skillContentPresent: false,
      contentCharCount: 0,
      contentLineCount: 0,
      itemCount: value.data.length,
      shareUrlCount,
      localPathCount,
      installedCount,
      enabledCount,
    };
  }
  return {
    method,
    skillContentPresent: Boolean(value?.skillContentPresent),
    contentCharCount: safeCount(value?.contentCharCount),
    contentLineCount: safeCount(value?.contentLineCount),
    itemCount: safeCount(value?.itemCount),
    shareUrlCount: safeCount(value?.shareUrlCount),
    localPathCount: safeCount(value?.localPathCount),
    installedCount: safeCount(value?.installedCount),
    enabledCount: safeCount(value?.enabledCount),
  };
}

