export function buildIntegrationActionPreflight(body, { workspace }) {
  const methodAudit = integrationMethodAudit();
  const method = validateIntegrationMutationMethod(body?.method, methodAudit);
  const auditEntry = methodAudit.find((entry) => entry.method === method);
  const target = validateIntegrationTarget(body?.target);
  const args = validateMcpArguments(body?.arguments);
  const category = auditEntry?.category ?? "integration-mutation";
  const risk = summarizeBlockedIntegrationActionRisk({
    method,
    category,
    target,
    argumentsValue: body?.arguments,
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
      toolTraffic: false,
    },
    action: {
      type: "integration-action-preflight",
      method,
      category,
      execution: "blocked",
      wouldMutateSettings: false,
      wouldStartAuthFlow: false,
      wouldInvokeTool: false,
      wouldReadResource: false,
      wouldReadPlugin: false,
      wouldInstallPlugin: false,
      appServerTouched: false,
      reason: "integration-mutation-pipeline-not-implemented",
    },
    integrationAction: {
      method,
      category,
      target,
      arguments: args,
      methodAllowedByAudit: true,
      risk,
    },
    policy: {
      readOnly: true,
      appServerTraffic: false,
      settingsWrites: false,
      authCallbacks: false,
      authMutations: false,
      toolInvocation: false,
      installsEnabled: false,
      sharingMutations: false,
      marketplaceMutations: false,
      targetReturned: false,
      argumentTextReturned: false,
      namesReturned: false,
      pathsReturned: false,
      urlsReturned: false,
      requiresApprovalPipeline: true,
      requiresIntegrationProvenance: true,
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

function summarizeBlockedIntegrationActionRisk({ method, category, target, argumentsValue }) {
  const argumentObject = parseIntegrationRiskArguments(argumentsValue);
  const shape = summarizeIntegrationRiskArgumentShape(argumentObject);
  return sanitizeIntegrationActionRisk({
    level: "high",
    methodFamily: integrationRiskFamily(method, category),
    methodBlockedByAudit: true,
    executionBlocked: true,
    appServerTraffic: false,
    requiresSpecificAudit: true,
    requiresApprovalPipeline: true,
    installSurface: method === "plugin/install",
    pluginSharingSurface: category === "plugins-share",
    marketplaceMutationSurface: category === "plugins-marketplace",
    externalConfigImportSurface: method === "externalAgentConfig/import",
    authCallbackSurface: category === "auth-callback",
    authMutationSurface: category === "auth-mutation",
    mcpAuthSurface: category === "mcp-auth",
    mcpToolSurface: category === "mcp-tool",
    settingsWriteSurface:
      category === "settings-write" ||
      category === "settings-mutation" ||
      category === "settings-import",
    settingsMutationSurface: category === "settings-mutation",
    skillsWriteSurface: category === "skills-write",
    targetPresent: Boolean(target?.present),
    targetCharCount: safeCount(target?.charCount),
    argumentObjectAccepted: Boolean(argumentObject),
    argumentKeyCount: shape.argumentKeyCount,
    stringArgumentCount: shape.stringArgumentCount,
    arrayArgumentCount: shape.arrayArgumentCount,
    nestedObjectCount: shape.nestedObjectCount,
    urlLikeArgumentCount: shape.urlLikeArgumentCount,
    pathLikeArgumentCount: shape.pathLikeArgumentCount,
    secretLikeArgumentCount: shape.secretLikeArgumentCount,
    sensitiveKeyCount: shape.sensitiveKeyCount,
    auth: summarizeAuthIntegrationRisk(method, argumentObject),
    mcp: summarizeMcpIntegrationRisk(method, argumentObject),
    settings: summarizeSettingsIntegrationRisk(method, argumentObject),
    pluginInstall: summarizePluginInstallRisk(argumentObject),
    pluginShare: summarizePluginShareRisk(method, argumentObject),
    marketplace: summarizeMarketplaceMutationRisk(method, argumentObject),
    externalImport: summarizeExternalConfigImportRisk(argumentObject),
  });
}

function parseIntegrationRiskArguments(value) {
  const raw = value == null ? "" : typeof value === "string" ? value : JSON.stringify(value);
  if (typeof raw !== "string" || raw.trim().length === 0) {
    return null;
  }
  try {
    const parsed = JSON.parse(raw.trim());
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function summarizeIntegrationRiskArgumentShape(argumentObject) {
  const summary = {
    argumentKeyCount: 0,
    stringArgumentCount: 0,
    arrayArgumentCount: 0,
    nestedObjectCount: 0,
    urlLikeArgumentCount: 0,
    pathLikeArgumentCount: 0,
    secretLikeArgumentCount: 0,
    sensitiveKeyCount: 0,
  };
  if (!argumentObject || typeof argumentObject !== "object" || Array.isArray(argumentObject)) {
    return summary;
  }
  summary.argumentKeyCount = Object.keys(argumentObject).length;
  const stack = [{ value: argumentObject, isRoot: true }];
  const seen = new Set();
  while (stack.length > 0) {
    const { value, isRoot = false } = stack.pop();
    if (!value || typeof value !== "object") {
      continue;
    }
    if (seen.has(value)) {
      continue;
    }
    seen.add(value);
    if (Array.isArray(value)) {
      summary.arrayArgumentCount += value.length;
      for (const item of value) {
        summarizeIntegrationRiskPrimitive(item, summary);
        if (item && typeof item === "object") {
          stack.push({ value: item });
        }
      }
      continue;
    }
    if (!isRoot) {
      summary.nestedObjectCount += 1;
    }
    for (const [key, child] of Object.entries(value)) {
      if (isSensitiveArgumentKey(key)) {
        summary.sensitiveKeyCount += 1;
      }
      summarizeIntegrationRiskPrimitive(child, summary);
      if (child && typeof child === "object") {
        stack.push({ value: child });
      }
    }
  }
  return summary;
}

function summarizeIntegrationRiskPrimitive(value, summary) {
  if (typeof value !== "string") {
    return;
  }
  summary.stringArgumentCount += 1;
  if (isUrlLikeArgument(value)) {
    summary.urlLikeArgumentCount += 1;
  }
  if (isPathLikeArgument(value)) {
    summary.pathLikeArgumentCount += 1;
  }
  if (SECRET_RESPONSE_PATTERN.test(value)) {
    summary.secretLikeArgumentCount += 1;
  }
}

function isSensitiveArgumentKey(key) {
  return /(?:token|secret|password|credential|api[_-]?key|authorization|auth)/i.test(key);
}

function isUrlLikeArgument(value) {
  return /^(?:https?|ssh|git|file):\/\//i.test(value) || /^[^@\s]+@[^:\s]+:[^\s]+$/.test(value);
}

function isPathLikeArgument(value) {
  return /^(?:~\/|\/|[A-Za-z]:[\\/])/.test(value);
}

function summarizePluginInstallRisk(argumentObject) {
  return {
    pluginNamePresent: hasNonEmptyString(argumentObject?.pluginName),
    remoteMarketplaceNamePresent: hasNonEmptyString(argumentObject?.remoteMarketplaceName),
    marketplacePathPresent: hasNonEmptyString(argumentObject?.marketplacePath),
  };
}

function summarizeAuthIntegrationRisk(method, argumentObject) {
  const loginType = typeof argumentObject?.type === "string" ? argumentObject.type : null;
  return {
    loginStartRequested: method === "account/login/start",
    loginCancelRequested: method === "account/login/cancel",
    logoutRequested: method === "account/logout",
    addCreditsEmailRequested: method === "account/sendAddCreditsNudgeEmail",
    apiKeyLoginRequested: method === "account/login/start" && loginType === "apiKey",
    chatgptLoginRequested: method === "account/login/start" && loginType === "chatgpt",
    deviceCodeLoginRequested:
      method === "account/login/start" && loginType === "chatgptDeviceCode",
    authTokenLoginRequested:
      method === "account/login/start" && loginType === "chatgptAuthTokens",
    loginTypePresent: hasNonEmptyString(loginType),
    credentialStringCount:
      (hasNonEmptyString(argumentObject?.apiKey) ? 1 : 0) +
      (hasNonEmptyString(argumentObject?.accessToken) ? 1 : 0),
    accountIdentifierPresent: hasNonEmptyString(argumentObject?.chatgptAccountId),
    planTypePresent: hasNonEmptyString(argumentObject?.chatgptPlanType),
    loginIdPresent: hasNonEmptyString(argumentObject?.loginId),
    streamlinedLoginRequested: argumentObject?.codexStreamlinedLogin === true,
  };
}

function summarizeMcpIntegrationRisk(method, argumentObject) {
  const toolArguments =
    argumentObject?.arguments &&
    typeof argumentObject.arguments === "object" &&
    !Array.isArray(argumentObject.arguments)
      ? argumentObject.arguments
      : null;
  const meta =
    argumentObject?._meta &&
    typeof argumentObject._meta === "object" &&
    !Array.isArray(argumentObject._meta)
      ? argumentObject._meta
      : null;
  return {
    oauthLoginRequested: method === "mcpServer/oauth/login",
    toolCallRequested: method === "mcpServer/tool/call",
    serverReloadRequested: method === "config/mcpServer/reload",
    serverNamePresent:
      hasNonEmptyString(argumentObject?.name) || hasNonEmptyString(argumentObject?.server),
    toolNamePresent: hasNonEmptyString(argumentObject?.tool),
    threadIdPresent: hasNonEmptyString(argumentObject?.threadId),
    scopeCount: Array.isArray(argumentObject?.scopes) ? argumentObject.scopes.length : 0,
    timeoutRequested: Number.isFinite(argumentObject?.timeoutSecs),
    toolArgumentsObjectAccepted: Boolean(toolArguments),
    toolArgumentKeyCount: toolArguments ? Object.keys(toolArguments).length : 0,
    metaObjectAccepted: Boolean(meta),
    metaKeyCount: meta ? Object.keys(meta).length : 0,
  };
}

function summarizeSettingsIntegrationRisk(method, argumentObject) {
  const edits = Array.isArray(argumentObject?.edits) ? argumentObject.edits : [];
  const enablement =
    argumentObject?.enablement &&
    typeof argumentObject.enablement === "object" &&
    !Array.isArray(argumentObject.enablement)
      ? argumentObject.enablement
      : {};
  const hasValue = hasOwnObjectProperty(argumentObject, "value");
  const value = hasValue ? argumentObject.value : null;
  return {
    configValueWriteRequested: method === "config/value/write",
    configBatchWriteRequested: method === "config/batchWrite",
    mcpServerReloadRequested: method === "config/mcpServer/reload",
    experimentalFeatureSetRequested: method === "experimentalFeature/enablement/set",
    skillsConfigWriteRequested: method === "skills/config/write",
    keyPathCount:
      (hasNonEmptyString(argumentObject?.keyPath) ? 1 : 0) +
      edits.filter((edit) => hasNonEmptyString(edit?.keyPath)).length,
    editCount: safeCount(edits.length),
    valuePresent: hasValue,
    valueObjectCount:
      (value && typeof value === "object" && !Array.isArray(value) ? 1 : 0) +
      edits.filter(
        (edit) => edit?.value && typeof edit.value === "object" && !Array.isArray(edit.value),
      ).length,
    valueArrayCount:
      (Array.isArray(value) ? 1 : 0) + edits.filter((edit) => Array.isArray(edit?.value)).length,
    mergeStrategyCount:
      (hasNonEmptyString(argumentObject?.mergeStrategy) ? 1 : 0) +
      edits.filter((edit) => hasNonEmptyString(edit?.mergeStrategy)).length,
    filePathPresent: hasNonEmptyString(argumentObject?.filePath),
    expectedVersionPresent: hasNonEmptyString(argumentObject?.expectedVersion),
    reloadUserConfigRequested: argumentObject?.reloadUserConfig === true,
    featureEnablementCount: Object.keys(enablement).length,
    requestedEnabledCount: Object.values(enablement).filter((value) => value === true).length,
    requestedDisabledCount: Object.values(enablement).filter((value) => value === false).length,
  };
}

function summarizePluginShareRisk(method, argumentObject) {
  const shareTargets = Array.isArray(argumentObject?.shareTargets)
    ? argumentObject.shareTargets
    : [];
  const summary = {
    saveRequested: method === "plugin/share/save",
    updateTargetsRequested: method === "plugin/share/updateTargets",
    deleteRequested: method === "plugin/share/delete",
    pluginPathPresent: hasNonEmptyString(argumentObject?.pluginPath),
    remotePluginIdPresent: hasNonEmptyString(argumentObject?.remotePluginId),
    discoverabilityPresent: hasNonEmptyString(argumentObject?.discoverability),
    shareTargetCount: safeCount(shareTargets.length),
    userTargetCount: 0,
    groupTargetCount: 0,
    workspaceTargetCount: 0,
    unknownPrincipalTypeCount: 0,
    principalIdCount: 0,
  };
  for (const target of shareTargets) {
    if (!target || typeof target !== "object" || Array.isArray(target)) {
      continue;
    }
    if (hasNonEmptyString(target.principalId)) {
      summary.principalIdCount += 1;
    }
    switch (target.principalType) {
      case "user":
        summary.userTargetCount += 1;
        break;
      case "group":
        summary.groupTargetCount += 1;
        break;
      case "workspace":
        summary.workspaceTargetCount += 1;
        break;
      default:
        summary.unknownPrincipalTypeCount += 1;
        break;
    }
  }
  return summary;
}

function summarizeMarketplaceMutationRisk(method, argumentObject) {
  const sparsePaths = Array.isArray(argumentObject?.sparsePaths) ? argumentObject.sparsePaths : [];
  return {
    addSourcePresent: method === "marketplace/add" && hasNonEmptyString(argumentObject?.source),
    refNamePresent: hasNonEmptyString(argumentObject?.refName),
    sparsePathCount: safeCount(sparsePaths.length),
    marketplaceNamePresent: hasNonEmptyString(argumentObject?.marketplaceName),
  };
}

function summarizeExternalConfigImportRisk(argumentObject) {
  const migrationItems = Array.isArray(argumentObject?.migrationItems)
    ? argumentObject.migrationItems
    : [];
  const summary = {
    migrationItemCount: safeCount(migrationItems.length),
    repoScopedMigrationItemCount: 0,
    pluginMigrationCount: 0,
    pluginNameReferenceCount: 0,
    marketplaceNameReferenceCount: 0,
    sessionMigrationCount: 0,
    commandMigrationCount: 0,
    hookMigrationCount: 0,
    mcpServerMigrationCount: 0,
    subagentMigrationCount: 0,
  };
  for (const item of migrationItems) {
    if (!item || typeof item !== "object" || Array.isArray(item)) {
      continue;
    }
    if (hasNonEmptyString(item.cwd)) {
      summary.repoScopedMigrationItemCount += 1;
    }
    const details = item.details && typeof item.details === "object" ? item.details : {};
    const plugins = Array.isArray(details.plugins) ? details.plugins : [];
    summary.pluginMigrationCount += plugins.length;
    for (const plugin of plugins) {
      if (!plugin || typeof plugin !== "object" || Array.isArray(plugin)) {
        continue;
      }
      if (hasNonEmptyString(plugin.marketplaceName)) {
        summary.marketplaceNameReferenceCount += 1;
      }
      if (Array.isArray(plugin.pluginNames)) {
        summary.pluginNameReferenceCount += plugin.pluginNames.length;
      }
    }
    summary.sessionMigrationCount += Array.isArray(details.sessions) ? details.sessions.length : 0;
    summary.commandMigrationCount += Array.isArray(details.commands) ? details.commands.length : 0;
    summary.hookMigrationCount += Array.isArray(details.hooks) ? details.hooks.length : 0;
    summary.mcpServerMigrationCount += Array.isArray(details.mcpServers)
      ? details.mcpServers.length
      : 0;
    summary.subagentMigrationCount += Array.isArray(details.subagents)
      ? details.subagents.length
      : 0;
  }
  return summary;
}

function summarizeReviewFeedbackRisk(method, argumentObject) {
  const reviewTarget =
    argumentObject?.target && typeof argumentObject.target === "object" && !Array.isArray(argumentObject.target)
      ? argumentObject.target
      : {};
  const reviewTargetType =
    typeof reviewTarget.type === "string" ? reviewTarget.type.trim() : "";
  const tags =
    argumentObject?.tags && typeof argumentObject.tags === "object" && !Array.isArray(argumentObject.tags)
      ? argumentObject.tags
      : {};
  return {
    threadIdPresent: hasNonEmptyString(argumentObject?.threadId),
    threadIdCharCount:
      typeof argumentObject?.threadId === "string" ? argumentObject.threadId.length : 0,
    reviewDeliveryInline: method === "review/start" && argumentObject?.delivery === "inline",
    reviewDeliveryDetached: method === "review/start" && argumentObject?.delivery === "detached",
    reviewTargetUncommitted: method === "review/start" && reviewTargetType === "uncommittedChanges",
    reviewTargetBaseBranch: method === "review/start" && reviewTargetType === "baseBranch",
    reviewTargetCommit: method === "review/start" && reviewTargetType === "commit",
    reviewTargetCustom: method === "review/start" && reviewTargetType === "custom",
    branchPresent: hasNonEmptyString(reviewTarget.branch),
    shaPresent: hasNonEmptyString(reviewTarget.sha),
    titlePresent: hasNonEmptyString(reviewTarget.title),
    instructionsCharCount:
      typeof reviewTarget.instructions === "string" ? reviewTarget.instructions.length : 0,
    classificationPresent: method === "feedback/upload" && hasNonEmptyString(argumentObject?.classification),
    reasonCharCount: typeof argumentObject?.reason === "string" ? argumentObject.reason.length : 0,
    includeLogsRequested: method === "feedback/upload" && argumentObject?.includeLogs === true,
    extraLogFileCount: Array.isArray(argumentObject?.extraLogFiles)
      ? argumentObject.extraLogFiles.length
      : 0,
    tagCount: method === "feedback/upload" ? Object.keys(tags).length : 0,
  };
}

function sanitizeIntegrationActionRisk(risk) {
  return {
    level: risk?.level === "high" ? "high" : "unknown",
    methodFamily: safeIntegrationRiskFamily(risk?.methodFamily),
    methodBlockedByAudit: Boolean(risk?.methodBlockedByAudit),
    executionBlocked: risk?.executionBlocked !== false,
    appServerTraffic: false,
    requiresSpecificAudit: risk?.requiresSpecificAudit !== false,
    requiresApprovalPipeline: risk?.requiresApprovalPipeline !== false,
    installSurface: Boolean(risk?.installSurface),
    pluginSharingSurface: Boolean(risk?.pluginSharingSurface),
    marketplaceMutationSurface: Boolean(risk?.marketplaceMutationSurface),
    externalConfigImportSurface: Boolean(risk?.externalConfigImportSurface),
    authCallbackSurface: Boolean(risk?.authCallbackSurface),
    authMutationSurface: Boolean(risk?.authMutationSurface),
    mcpAuthSurface: Boolean(risk?.mcpAuthSurface),
    mcpToolSurface: Boolean(risk?.mcpToolSurface),
    settingsWriteSurface: Boolean(risk?.settingsWriteSurface),
    settingsMutationSurface: Boolean(risk?.settingsMutationSurface),
    skillsWriteSurface: Boolean(risk?.skillsWriteSurface),
    targetPresent: Boolean(risk?.targetPresent),
    targetCharCount: safeCount(risk?.targetCharCount),
    argumentObjectAccepted: Boolean(risk?.argumentObjectAccepted),
    argumentKeyCount: safeCount(risk?.argumentKeyCount),
    stringArgumentCount: safeCount(risk?.stringArgumentCount),
    arrayArgumentCount: safeCount(risk?.arrayArgumentCount),
    nestedObjectCount: safeCount(risk?.nestedObjectCount),
    urlLikeArgumentCount: safeCount(risk?.urlLikeArgumentCount),
    pathLikeArgumentCount: safeCount(risk?.pathLikeArgumentCount),
    secretLikeArgumentCount: safeCount(risk?.secretLikeArgumentCount),
    sensitiveKeyCount: safeCount(risk?.sensitiveKeyCount),
    auth: sanitizeAuthIntegrationRisk(risk?.auth),
    mcp: sanitizeMcpIntegrationRisk(risk?.mcp),
    settings: sanitizeSettingsIntegrationRisk(risk?.settings),
    pluginInstall: sanitizePluginInstallRisk(risk?.pluginInstall),
    pluginShare: sanitizePluginShareRisk(risk?.pluginShare),
    marketplace: sanitizeMarketplaceMutationRisk(risk?.marketplace),
    externalImport: sanitizeExternalConfigImportRisk(risk?.externalImport),
    targetReturned: false,
    argumentTextReturned: false,
    namesReturned: false,
    marketplaceNamesReturned: false,
    pluginNamesReturned: false,
    shareTargetsReturned: false,
    principalIdsReturned: false,
    principalsReturned: false,
    pathsReturned: false,
    urlsReturned: false,
    secretsReturned: false,
    rawPayloadReturned: false,
  };
}

function sanitizePluginInstallRisk(risk) {
  return {
    pluginNamePresent: Boolean(risk?.pluginNamePresent),
    remoteMarketplaceNamePresent: Boolean(risk?.remoteMarketplaceNamePresent),
    marketplacePathPresent: Boolean(risk?.marketplacePathPresent),
  };
}

function sanitizeAuthIntegrationRisk(risk) {
  return {
    loginStartRequested: Boolean(risk?.loginStartRequested),
    loginCancelRequested: Boolean(risk?.loginCancelRequested),
    logoutRequested: Boolean(risk?.logoutRequested),
    addCreditsEmailRequested: Boolean(risk?.addCreditsEmailRequested),
    apiKeyLoginRequested: Boolean(risk?.apiKeyLoginRequested),
    chatgptLoginRequested: Boolean(risk?.chatgptLoginRequested),
    deviceCodeLoginRequested: Boolean(risk?.deviceCodeLoginRequested),
    authTokenLoginRequested: Boolean(risk?.authTokenLoginRequested),
    loginTypePresent: Boolean(risk?.loginTypePresent),
    credentialStringCount: safeCount(risk?.credentialStringCount),
    accountIdentifierPresent: Boolean(risk?.accountIdentifierPresent),
    planTypePresent: Boolean(risk?.planTypePresent),
    loginIdPresent: Boolean(risk?.loginIdPresent),
    streamlinedLoginRequested: Boolean(risk?.streamlinedLoginRequested),
  };
}

function sanitizeMcpIntegrationRisk(risk) {
  return {
    oauthLoginRequested: Boolean(risk?.oauthLoginRequested),
    toolCallRequested: Boolean(risk?.toolCallRequested),
    serverReloadRequested: Boolean(risk?.serverReloadRequested),
    serverNamePresent: Boolean(risk?.serverNamePresent),
    toolNamePresent: Boolean(risk?.toolNamePresent),
    threadIdPresent: Boolean(risk?.threadIdPresent),
    scopeCount: safeCount(risk?.scopeCount),
    timeoutRequested: Boolean(risk?.timeoutRequested),
    toolArgumentsObjectAccepted: Boolean(risk?.toolArgumentsObjectAccepted),
    toolArgumentKeyCount: safeCount(risk?.toolArgumentKeyCount),
    metaObjectAccepted: Boolean(risk?.metaObjectAccepted),
    metaKeyCount: safeCount(risk?.metaKeyCount),
  };
}

function sanitizeSettingsIntegrationRisk(risk) {
  return {
    configValueWriteRequested: Boolean(risk?.configValueWriteRequested),
    configBatchWriteRequested: Boolean(risk?.configBatchWriteRequested),
    mcpServerReloadRequested: Boolean(risk?.mcpServerReloadRequested),
    experimentalFeatureSetRequested: Boolean(risk?.experimentalFeatureSetRequested),
    skillsConfigWriteRequested: Boolean(risk?.skillsConfigWriteRequested),
    keyPathCount: safeCount(risk?.keyPathCount),
    editCount: safeCount(risk?.editCount),
    valuePresent: Boolean(risk?.valuePresent),
    valueObjectCount: safeCount(risk?.valueObjectCount),
    valueArrayCount: safeCount(risk?.valueArrayCount),
    mergeStrategyCount: safeCount(risk?.mergeStrategyCount),
    filePathPresent: Boolean(risk?.filePathPresent),
    expectedVersionPresent: Boolean(risk?.expectedVersionPresent),
    reloadUserConfigRequested: Boolean(risk?.reloadUserConfigRequested),
    featureEnablementCount: safeCount(risk?.featureEnablementCount),
    requestedEnabledCount: safeCount(risk?.requestedEnabledCount),
    requestedDisabledCount: safeCount(risk?.requestedDisabledCount),
  };
}

function sanitizePluginShareRisk(risk) {
  return {
    saveRequested: Boolean(risk?.saveRequested),
    updateTargetsRequested: Boolean(risk?.updateTargetsRequested),
    deleteRequested: Boolean(risk?.deleteRequested),
    pluginPathPresent: Boolean(risk?.pluginPathPresent),
    remotePluginIdPresent: Boolean(risk?.remotePluginIdPresent),
    discoverabilityPresent: Boolean(risk?.discoverabilityPresent),
    shareTargetCount: safeCount(risk?.shareTargetCount),
    userTargetCount: safeCount(risk?.userTargetCount),
    groupTargetCount: safeCount(risk?.groupTargetCount),
    workspaceTargetCount: safeCount(risk?.workspaceTargetCount),
    unknownPrincipalTypeCount: safeCount(risk?.unknownPrincipalTypeCount),
    principalIdCount: safeCount(risk?.principalIdCount),
  };
}

function sanitizeMarketplaceMutationRisk(risk) {
  return {
    addSourcePresent: Boolean(risk?.addSourcePresent),
    refNamePresent: Boolean(risk?.refNamePresent),
    sparsePathCount: safeCount(risk?.sparsePathCount),
    marketplaceNamePresent: Boolean(risk?.marketplaceNamePresent),
  };
}

function sanitizeExternalConfigImportRisk(risk) {
  return {
    migrationItemCount: safeCount(risk?.migrationItemCount),
    repoScopedMigrationItemCount: safeCount(risk?.repoScopedMigrationItemCount),
    pluginMigrationCount: safeCount(risk?.pluginMigrationCount),
    pluginNameReferenceCount: safeCount(risk?.pluginNameReferenceCount),
    marketplaceNameReferenceCount: safeCount(risk?.marketplaceNameReferenceCount),
    sessionMigrationCount: safeCount(risk?.sessionMigrationCount),
    commandMigrationCount: safeCount(risk?.commandMigrationCount),
    hookMigrationCount: safeCount(risk?.hookMigrationCount),
    mcpServerMigrationCount: safeCount(risk?.mcpServerMigrationCount),
    subagentMigrationCount: safeCount(risk?.subagentMigrationCount),
  };
}

function integrationRiskFamily(method, category) {
  if (method === "plugin/install") {
    return "plugin-install";
  }
  if (category === "plugins-marketplace") {
    return "plugin-marketplace";
  }
  if (method === "externalAgentConfig/import") {
    return "external-config-import";
  }
  if (category === "plugins-share") {
    return "plugin-share";
  }
  if (category === "auth-callback" || category === "auth-mutation") {
    return "auth";
  }
  if (category === "mcp-tool" || category === "mcp-auth") {
    return "mcp";
  }
  if (category === "settings-write" || category === "settings-mutation") {
    return "settings-write";
  }
  if (category === "settings-import") {
    return "settings-import";
  }
  if (category === "skills-write") {
    return "skills-write";
  }
  if (category === "plugins-install" || category === "plugins-share") {
    return "plugin-mutation";
  }
  return "blocked-mutation";
}

function safeIntegrationRiskFamily(value) {
  return [
    "plugin-install",
    "plugin-share",
    "plugin-marketplace",
    "external-config-import",
    "auth",
    "mcp",
    "settings-write",
    "settings-import",
    "skills-write",
    "plugin-mutation",
    "blocked-mutation",
  ].includes(value)
    ? value
    : "blocked-mutation";
}

function hasNonEmptyString(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function hasOwnObjectProperty(value, key) {
  return Boolean(value && typeof value === "object" && Object.hasOwn(value, key));
}

function sanitizeIntegrationPreflightHistory(records) {
  const items = Array.isArray(records)
    ? records.slice(0, MAX_INTEGRATION_PREFLIGHT_HISTORY_RECORDS).map((record) =>
        sanitizeIntegrationPreflightHistoryRecord(record),
      )
    : [];
  return {
    count: items.length,
    items,
    limit: MAX_INTEGRATION_PREFLIGHT_HISTORY_RECORDS,
    preflightTokensReturned: false,
    namesReturned: false,
    targetReturned: false,
    argumentTextReturned: false,
    schemasReturned: false,
    pathsReturned: false,
    urlsReturned: false,
    toolInvocationEnabled: false,
    resourceReadEnabled: false,
    pluginReadEnabled: false,
    pluginContentReadEnabled: false,
    pluginShareListEnabled: false,
    mutationsEnabled: false,
  };
}

function sanitizeIntegrationPreflightHistoryRecord(record, { recordedAt = null } = {}) {
  const action = record?.action ?? {};
  const args = record?.arguments ?? record?.integrationAction?.arguments ?? {};
  const integrationAction = record?.integrationAction ?? {};
  const mcpTool = record?.mcpTool ?? {};
  const mcpResource = record?.mcpResource ?? {};
  const server = record?.server ?? {};
  const tool = record?.tool ?? {};
  const resource = record?.resource ?? {};
  const actionType =
    isIntegrationPreflightActionType(action.type)
      ? action.type
      : integrationAction.method
        ? "integration-action-preflight"
        : "mcp-tool-preflight";
  return {
    recordedAt: cleanDisplayText(recordedAt ?? record?.recordedAt, 40),
    workspace: record?.workspace
      ? {
          id: cleanDisplayText(record.workspace.id, 80),
          label: cleanDisplayText(record.workspace.label, 120),
          isDefault: Boolean(record.workspace.isDefault),
        }
      : null,
    action: {
      type: actionType,
      method:
        cleanDisplayText(action.method, 100) ??
        cleanDisplayText(integrationAction.method, 100) ??
        (actionType === "mcp-tool-preflight"
          ? "mcpServer/tool/call"
          : actionType === "mcp-resource-preflight"
            ? "mcpServer/resource/read"
            : "unknown"),
      category: cleanDisplayText(action.category ?? integrationAction.category, 80),
      execution: "blocked",
      wouldMutateSettings: false,
      wouldStartAuthFlow: false,
      wouldInvokeTool: false,
      wouldReadResource: false,
      wouldReadPlugin: false,
      wouldReadPluginContent: false,
      wouldReadPluginShares: false,
      wouldInstallPlugin: false,
      appServerTouched: false,
    },
    mcpTool: {
      serverCharCount: safeCount(server.charCount ?? mcpTool.serverCharCount),
      toolCharCount: safeCount(tool.charCount ?? mcpTool.toolCharCount),
      argumentCharCount: safeCount(args.charCount ?? mcpTool.argumentCharCount),
      argumentTopLevelKeyCount: safeCount(
        args.topLevelKeyCount ?? mcpTool.argumentTopLevelKeyCount,
      ),
      namesReturned: false,
      argumentTextReturned: false,
      schemasReturned: false,
    },
    mcpResource: {
      serverCharCount: safeCount(server.charCount ?? mcpResource.serverCharCount),
      resourceCharCount: safeCount(resource.charCount ?? mcpResource.resourceCharCount),
      namesReturned: false,
      resourceUriReturned: false,
      resourceContentReturned: false,
      schemasReturned: false,
    },
    integrationAction: {
      method: cleanDisplayText(integrationAction.method, 100),
      category: cleanDisplayText(integrationAction.category, 80),
      targetCharCount: safeCount(integrationAction.target?.charCount ?? integrationAction.targetCharCount),
      argumentCharCount: safeCount(
        integrationAction.arguments?.charCount ?? integrationAction.argumentCharCount,
      ),
      argumentTopLevelKeyCount: safeCount(
        integrationAction.arguments?.topLevelKeyCount ?? integrationAction.argumentTopLevelKeyCount,
      ),
      methodAllowedByAudit: Boolean(integrationAction.methodAllowedByAudit),
      risk: integrationAction.risk ? sanitizeIntegrationActionRisk(integrationAction.risk) : null,
      targetReturned: false,
      argumentTextReturned: false,
      namesReturned: false,
      pathsReturned: false,
      urlsReturned: false,
    },
    preflight: {
      tokenIssued: Boolean(record?.preflight?.token || record?.preflight?.tokenIssued),
      tokenReturned: false,
      rawIntentStored: false,
      rawIntentReturned: false,
      intentHashReturned: false,
    },
    policy: {
      readOnly: true,
      appServerTraffic: false,
      toolInvocation: false,
      resourceRead: false,
      pluginRead: false,
      pluginContentRead: false,
      pluginShareList: false,
      settingsWrites: false,
      authCallbacks: false,
      authMutations: false,
      installsEnabled: false,
      sharingMutations: false,
      marketplaceMutations: false,
      preflightTokenReturned: false,
      namesReturned: false,
      targetReturned: false,
      argumentTextReturned: false,
      schemasReturned: false,
      pathsReturned: false,
      urlsReturned: false,
    },
  };
}

function sanitizeIntegrationPreflightConfirmationHistory(records) {
  const items = Array.isArray(records)
    ? records.slice(0, MAX_INTEGRATION_PREFLIGHT_CONFIRMATION_HISTORY_RECORDS).map((record) =>
        sanitizeIntegrationPreflightConfirmationHistoryRecord(record),
      )
    : [];
  return {
    count: items.length,
    items,
    limit: MAX_INTEGRATION_PREFLIGHT_CONFIRMATION_HISTORY_RECORDS,
    preflightTokensConsumed: items.some((item) => item.preflight?.tokenConsumed),
    preflightTokensReturned: false,
    namesReturned: false,
    targetReturned: false,
    argumentTextReturned: false,
    schemasReturned: false,
    pathsReturned: false,
    urlsReturned: false,
    rawIntentReturned: false,
    intentHashesReturned: false,
    toolInvocationEnabled: false,
    resourceReadEnabled: false,
    pluginReadEnabled: false,
    pluginContentReadEnabled: false,
    pluginShareListEnabled: false,
    mutationsEnabled: false,
  };
}

function sanitizeIntegrationPreflightConfirmationHistoryRecord(
  record,
  { recordedAt = null } = {},
) {
  const confirmation = record?.confirmation ?? {};
  const source = record?.payload ?? record ?? {};
  const action = confirmation.action ?? source.action ?? {};
  const integrationAction = source.integrationAction ?? record?.integrationAction ?? {};
  const mcpTool = record?.mcpTool ?? {};
  const mcpResource = record?.mcpResource ?? {};
  const server = source.server ?? record?.server ?? {};
  const tool = source.tool ?? record?.tool ?? {};
  const resource = source.resource ?? record?.resource ?? {};
  const args = source.arguments ?? source.integrationAction?.arguments ?? record?.arguments ?? {};
  const preflight = confirmation.preflight ?? record?.preflight ?? {};
  const actionType = isIntegrationPreflightActionType(action.type)
    ? action.type
    : integrationAction.method
      ? "integration-action-preflight"
      : "mcp-tool-preflight";
  const workspace = confirmation.workspace ?? source.workspace ?? record?.workspace;
  return {
    recordedAt: cleanDisplayText(recordedAt ?? record?.recordedAt, 40),
    workspace: workspace
      ? {
          id: cleanDisplayText(workspace.id, 80),
          label: cleanDisplayText(workspace.label, 120),
          isDefault: Boolean(workspace.isDefault),
        }
      : null,
    action: {
      type: actionType,
      method:
        cleanDisplayText(action.method, 100) ??
        cleanDisplayText(integrationAction.method, 100) ??
        (actionType === "mcp-tool-preflight"
          ? "mcpServer/tool/call"
          : actionType === "mcp-resource-preflight"
            ? "mcpServer/resource/read"
            : "unknown"),
      category: cleanDisplayText(action.category ?? integrationAction.category, 80),
      execution: "blocked",
      preflightConfirmed: true,
      mutationExecuted: false,
      wouldMutateSettings: false,
      wouldStartAuthFlow: false,
      wouldInvokeTool: false,
      wouldReadPlugin: false,
      wouldReadPluginContent: false,
      wouldReadPluginShares: false,
      wouldInstallPlugin: false,
      appServerTouched: false,
    },
    mcpTool: {
      serverCharCount: safeCount(server.charCount ?? mcpTool.serverCharCount),
      toolCharCount: safeCount(tool.charCount ?? mcpTool.toolCharCount),
      argumentCharCount: safeCount(args.charCount ?? mcpTool.argumentCharCount),
      argumentTopLevelKeyCount: safeCount(
        args.topLevelKeyCount ?? mcpTool.argumentTopLevelKeyCount,
      ),
      namesReturned: false,
      argumentTextReturned: false,
      schemasReturned: false,
    },
    mcpResource: {
      serverCharCount: safeCount(server.charCount ?? mcpResource.serverCharCount),
      resourceCharCount: safeCount(resource.charCount ?? mcpResource.resourceCharCount),
      namesReturned: false,
      resourceUriReturned: false,
      resourceContentReturned: false,
      schemasReturned: false,
    },
    integrationAction: {
      method: cleanDisplayText(integrationAction.method, 100),
      category: cleanDisplayText(integrationAction.category, 80),
      targetCharCount: safeCount(
        integrationAction.target?.charCount ?? integrationAction.targetCharCount,
      ),
      argumentCharCount: safeCount(
        integrationAction.arguments?.charCount ?? integrationAction.argumentCharCount,
      ),
      argumentTopLevelKeyCount: safeCount(
        integrationAction.arguments?.topLevelKeyCount ?? integrationAction.argumentTopLevelKeyCount,
      ),
      methodAllowedByAudit: Boolean(integrationAction.methodAllowedByAudit),
      risk: integrationAction.risk ? sanitizeIntegrationActionRisk(integrationAction.risk) : null,
      targetReturned: false,
      argumentTextReturned: false,
      namesReturned: false,
      pathsReturned: false,
      urlsReturned: false,
    },
    preflight: {
      tokenConsumed: Boolean(preflight.tokenConsumed),
      tokenReturned: false,
      workspaceId: cleanDisplayText(preflight.scope?.workspaceId ?? preflight.workspaceId, 80),
      rawIntentStored: false,
      rawIntentReturned: false,
      intentHashReturned: false,
      oneTimeUseEnforced: preflight.oneTimeUseEnforced !== false,
    },
    policy: {
      readOnly: true,
      appServerTraffic: false,
      modelTraffic: false,
      commandExecution: false,
      filesystemWrites: false,
      gitWrites: false,
      toolInvocation: false,
      resourceRead: false,
      pluginRead: false,
      pluginContentRead: false,
      pluginShareList: false,
      mutationExecuted: false,
      settingsWrites: false,
      authCallbacks: false,
      authMutations: false,
      installsEnabled: false,
      sharingMutations: false,
      marketplaceMutations: false,
      preflightTokenReturned: false,
      namesReturned: false,
      targetReturned: false,
      argumentTextReturned: false,
      schemasReturned: false,
      pathsReturned: false,
      urlsReturned: false,
    },
  };
}

