function buildCodexAppSettingsParity(payload = {}) {
  const integrationScope = payload.integrationScope ?? {};
  const general = buildCodexAppGeneralSettingsSummary();
  const agentConfiguration = buildCodexAppAgentConfigurationSettingsSummary();
  const keyboardShortcuts = buildCodexAppKeyboardShortcutsSummary();
  const profile = buildCodexAppProfileSettingsSummary();
  const appearance = buildCodexAppAppearanceSettingsSummary();
  const codexPets = buildCodexAppPetSettingsSummary();
  const git = buildCodexAppGitSettingsSummary();
  const integrationsMcp = buildCodexAppIntegrationsMcpSettingsSummary(integrationScope);
  const browser = buildCodexAppBrowserSettingsSummary();
  const computerUse = buildCodexAppComputerUseSettingsSummary();
  const contextAwareSuggestions = buildCodexAppContextAwareSuggestionsSettingsSummary();
  const notifications = buildCodexAppNotificationSettingsSummary(payload);
  const personalization = buildCodexAppPersonalizationSettingsSummary();
  const memories = buildCodexAppMemoriesSettingsSummary(integrationScope);
  const archivedThreads = buildCodexAppArchivedThreadsSettingsSummary();
  const sections = [
    codexAppSettingsSection(
      "general",
      "core",
      general.state,
      "general-settings-catalog",
    ),
    codexAppSettingsSection(
      "profile",
      "account",
      profile.state,
      "profile-settings-catalog",
    ),
    codexAppSettingsSection(
      "keyboardShortcuts",
      "interface",
      keyboardShortcuts.state,
      "keyboard-shortcuts-catalog",
    ),
    codexAppSettingsSection(
      "notifications",
      "interface",
      notifications.state,
      "notification-settings-catalog",
    ),
    codexAppSettingsSection(
      "agentConfiguration",
      "agent",
      agentConfiguration.state,
      "agent-configuration-settings-catalog",
    ),
    codexAppSettingsSection(
      "appearance",
      "interface",
      appearance.state,
      "appearance-settings-catalog",
    ),
    codexAppSettingsSection("codexPets", "interface", codexPets.state, "pet-settings-catalog"),
    codexAppSettingsSection("git", "workspace", git.state, "git-settings-catalog"),
    codexAppSettingsSection(
      "integrationsMcp",
      "integrations",
      integrationsMcp.state,
      "integrations-mcp-settings-catalog",
    ),
    codexAppSettingsSection(
      "browser",
      "runtime",
      browser.state,
      "browser-settings-catalog",
    ),
    codexAppSettingsSection(
      "computerUse",
      "runtime",
      computerUse.state,
      "computer-use-settings-catalog",
    ),
    codexAppSettingsSection(
      "personalization",
      "agent",
      personalization.state,
      "personalization-settings-catalog",
    ),
    codexAppSettingsSection(
      "contextAwareSuggestions",
      "agent",
      contextAwareSuggestions.state,
      "context-aware-suggestions-catalog",
    ),
    codexAppSettingsSection(
      "memories",
      "agent",
      memories.state,
      "memories-settings-catalog",
    ),
    codexAppSettingsSection(
      "archivedThreads",
      "threads",
      archivedThreads.state,
      "archived-threads-settings-catalog",
    ),
  ];
  const blockedSectionCount = sections.filter((section) => section.state === "blocked").length;
  const preflightOnlySectionCount = sections.filter(
    (section) => section.state === "preflight-only",
  ).length;
  const partialSectionCount = sections.filter((section) => section.state === "partial").length;
  return {
    returned: true,
    state: blockedSectionCount > 0 ? "partial" : "complete",
    officialSource: "openai-codex-app-settings-docs",
    officialSectionCount: CODEX_APP_SETTINGS_PARITY_SECTION_KEYS.length,
    trackedSectionCount: sections.length,
    availableSectionCount: sections.length - blockedSectionCount,
    partialSectionCount,
    preflightOnlySectionCount,
    blockedSectionCount,
    sections,
    general,
    agentConfiguration,
    profile,
    keyboardShortcuts,
    appearance,
    codexPets,
    git,
    integrationsMcp,
    browser,
    computerUse,
    contextAwareSuggestions,
    notifications,
    personalization,
    memories,
    archivedThreads,
    sectionKeysReturned: true,
    sectionLabelsReturned: false,
    localSettingValuesReturned: false,
    settingValuesReturned: false,
    localNamesReturned: false,
    pathsReturned: false,
    urlsReturned: false,
    secretsReturned: false,
    rawPayloadsReturned: false,
    createdAppServerTraffic: false,
    appServerTraffic: false,
    appServerPayloadReturned: false,
    mutationsEnabled: false,
    browserHandlersEnabled: false,
    settingsWritesEnabled: false,
  };
}

