export function sanitizeAccountLoginPayload(
  payload,
  {
    workspace = null,
    consumedPreflight,
    loginFlowRecord = null,
    actionAuditLog = null,
    auditLogWritableChecked = false,
  } = {},
) {
  const accountLoginStart = sanitizeAccountLoginStartProbe(payload?.probes?.accountLoginStart);
  const deviceCodeFlow = accountLoginStart.resultType === "chatgptDeviceCode";
  const userCode = deviceCodeFlow ? accountLoginStart.userCode : null;
  const verificationUrl = deviceCodeFlow ? accountLoginStart.verificationUrl : null;
  const cancelRef = safeAccountLoginRef(loginFlowRecord?.loginRef);
  const cancelAvailable = Boolean(cancelRef);
  const safeDevicePayload = Boolean(userCode && verificationUrl);
  const status = safeDevicePayload ? "device-code-issued" : "started-with-redactions";
  return {
    ok: Boolean(payload?.ok && deviceCodeFlow),
    generatedAt: payload?.generatedAt ?? new Date().toISOString(),
    transport: cleanDisplayText(payload?.transport, 80),
    protocol: cleanDisplayText(payload?.protocol, 80),
    initialize: sanitizeInitialize(payload?.initialize),
    workspace: workspace ? publicWorkspaces([workspace])[0] : null,
    appServer: {
      touched: true,
      modelTraffic: false,
      commandTraffic: false,
      auditedMethods: ["account/login/start"],
    },
    action: {
      type: "account-login",
      method: "account/login/start",
      execution: status,
      authMutation: true,
      authFlowStarted: true,
      appServerTouched: true,
      modelTraffic: false,
    },
    preflight: buildConsumedPreflightSummary(consumedPreflight),
    target: {
      loginType: "chatgptDeviceCode",
      accountIdentifiersReturned: false,
      tokensReturned: false,
      loginIdReturned: false,
      cancelRefReturned: Boolean(cancelRef),
      authUrlReturned: false,
      verificationUrlReturned: Boolean(verificationUrl),
      userCodeReturned: Boolean(userCode),
    },
    auth: {
      loginType: "chatgptDeviceCode",
      deviceCodeFlow,
      userCode,
      verificationUrl,
      cancelRef,
      cancelAvailable,
      userCodeReturned: Boolean(userCode),
      verificationUrlReturned: Boolean(verificationUrl),
      loginIdReturned: false,
      cancelRefReturned: Boolean(cancelRef),
      authUrlReturned: false,
      apiKeyFlowAccepted: false,
      chatgptAuthTokensAccepted: false,
      tokensReturned: false,
      accountIdentifiersReturned: false,
    },
    probes: {
      accountLoginStart,
    },
    result: {
      status,
      resultType: accountLoginStart.resultType,
      deviceCodeFlow,
      cancelAvailable,
      cancelRefReturned: Boolean(cancelRef),
      userCodeReturned: Boolean(userCode),
      verificationUrlReturned: Boolean(verificationUrl),
      loginIdReturned: false,
      authUrlReturned: false,
      tokensReturned: false,
      accountIdentifiersReturned: false,
      rawPayloadReturned: false,
      threadContentReturned: false,
      fullIdsReturned: false,
    },
    policy: {
      readOnly: false,
      appServerTraffic: true,
      modelTraffic: false,
      commandTraffic: false,
      settingsWrites: false,
      authCallbacks: false,
      authMutations: true,
      authDeviceCodeOnly: true,
      toolInvocation: false,
      installsEnabled: false,
      promptTextReturned: false,
      secretsReturned: false,
      tokensReturned: false,
      accountIdentifiersReturned: false,
      loginIdsReturned: false,
      loginRefsReturned: Boolean(cancelRef),
      authUrlsReturned: false,
      verificationUrlsReturned: Boolean(verificationUrl),
      userCodesReturned: Boolean(userCode),
      urlsReturned: Boolean(verificationUrl),
      pathsReturned: false,
      rawPayloadReturned: false,
      requiresExplicitEnablement: true,
      preflightTokenConsumed: true,
      auditLogPersistent: Boolean(actionAuditLog?.persistent),
      auditLogWritableChecked: Boolean(auditLogWritableChecked),
      auditLogWritten: false,
      auditLogPathReturned: false,
      browserMethodCallsAccepted: true,
      implemented: true,
      requiresExplicitExecutionGate: true,
    },
    notifications: sanitizeNotificationCounts(payload?.notifications),
  };
}

function sanitizeAccountLoginHistory(records) {
  const items = Array.isArray(records)
    ? records.slice(0, MAX_ACCOUNT_LOGIN_HISTORY_RECORDS).map((record) =>
        sanitizeAccountLoginHistoryRecord(record),
      )
    : [];
  return {
    count: items.length,
    items,
    limit: MAX_ACCOUNT_LOGIN_HISTORY_RECORDS,
    appServerTraffic: items.some((item) => item.action?.appServerTouched),
    authFlowsRecorded: items.some((item) => item.action?.authFlowStarted),
    authCancelsRecorded: items.some((item) => item.action?.authFlowCanceled),
    preflightTokensReturned: false,
    userCodesReturned: false,
    verificationUrlsReturned: false,
    loginIdsReturned: false,
    loginRefsReturned: false,
    authUrlsReturned: false,
    tokensReturned: false,
    accountIdentifiersReturned: false,
    pathsReturned: false,
    rawPayloadsReturned: false,
  };
}

function sanitizeAccountLoginHistoryRecord(record, { recordedAt = null } = {}) {
  const action = record?.action ?? {};
  const result = record?.result ?? {};
  const preflight = record?.preflight ?? {};
  const policy = record?.policy ?? {};
  const actionType = action.type === "account-login-cancel" ? "account-login-cancel" : "account-login";
  const isCancel = actionType === "account-login-cancel";
  return {
    recordedAt: cleanDisplayText(recordedAt ?? record?.recordedAt, 40),
    workspace: record?.workspace
      ? {
          id: cleanDisplayText(record.workspace.id, 80),
          label: cleanDisplayText(record.workspace.label, 120),
          isDefault: Boolean(record.workspace.isDefault),
        }
      : null,
    action: {
      type: actionType,
      method: isCancel ? "account/login/cancel" : "account/login/start",
      execution: cleanDisplayText(action.execution, 40) ?? "unknown",
      authMutation: Boolean(action.authMutation),
      authFlowStarted: isCancel ? false : Boolean(action.authFlowStarted),
      authFlowCanceled: isCancel ? Boolean(action.authFlowCanceled) : false,
      appServerTouched: Boolean(action.appServerTouched),
      modelTraffic: false,
    },
    result: {
      status: cleanDisplayText(result.status, 80),
      resultType: isCancel ? null : cleanDisplayText(result.resultType, 40),
      deviceCodeFlow: isCancel ? false : Boolean(result.deviceCodeFlow),
      canceled: isCancel ? Boolean(result.canceled) : false,
      notFound: isCancel ? Boolean(result.notFound) : false,
      cancelRefReturned: false,
      userCodeReturned: false,
      verificationUrlReturned: false,
      loginIdReturned: false,
      loginRefReturned: false,
      authUrlReturned: false,
      tokensReturned: false,
      accountIdentifiersReturned: false,
      rawPayloadReturned: false,
      threadContentReturned: false,
      fullIdsReturned: false,
    },
    preflight: {
      tokenConsumed: Boolean(preflight.tokenConsumed),
      tokenReturned: false,
      workspaceId: cleanDisplayText(preflight.scope?.workspaceId ?? preflight.workspaceId, 80),
      rawIntentStored: false,
      rawIntentReturned: false,
      intentHashReturned: false,
      oneTimeUseEnforced: preflight.oneTimeUseEnforced !== false,
    },
    policy: {
      readOnly: false,
      appServerTraffic: Boolean(policy.appServerTraffic),
      authMutations: Boolean(policy.authMutations),
      authDeviceCodeOnly: policy.authDeviceCodeOnly !== false,
      modelTraffic: false,
      secretsReturned: false,
      tokensReturned: false,
      accountIdentifiersReturned: false,
      loginIdsReturned: false,
      loginRefsReturned: false,
      authUrlsReturned: false,
      verificationUrlsReturned: false,
      userCodesReturned: false,
      urlsReturned: false,
      pathsReturned: false,
      rawPayloadReturned: false,
      preflightTokenReturned: false,
      auditLogPersistent: Boolean(policy.auditLogPersistent),
      auditLogWritableChecked: Boolean(policy.auditLogWritableChecked),
      auditLogWritten: Boolean(policy.auditLogWritten),
      auditLogPathReturned: false,
      sensitivePayloadLogged: false,
      browserMethodCallsAccepted: Boolean(policy.browserMethodCallsAccepted),
      implemented: Boolean(policy.implemented),
    },
  };
}

