export function buildTurnStartBlocked(body, { workspace, options = {} }) {
  const draft = buildTurnDraftMetadata(body, { workspace });
  const gate = buildExecutionGate({ workspace, options });
  return {
    ok: false,
    generatedAt: new Date().toISOString(),
    error:
      "Turn execution is disabled. Use /api/turn-preflight; real turn/start requires the execution gate and approval pipeline.",
    workspace: draft.workspace,
    gate: gate.gate,
    action: gate.action,
    target: draft.target,
    prompt: draft.prompt,
    policy: gate.policy,
  };
}

function summarizeTurnExecutionReadiness({
  options = {},
  pendingApprovalCount = 0,
  threadLifecycleActionHistory = {},
} = {}) {
  const turnStartEnabled = Boolean(options.turnStartEnabled);
  const sessionManagerEnabled = Boolean(options.sessionManagerEnabled);
  const approvalForwardingGateEnabled = isApprovalForwardingGateEnabled(options);
  const approvalAcceptGateEnabled = isApprovalAcceptGateEnabled(options);
  const safePendingApprovalCount = safeCount(pendingApprovalCount);
  const recentThreadLifecycleActionCount = safeCount(threadLifecycleActionHistory.count);
  return {
    returned: true,
    state: turnStartEnabled
      ? safePendingApprovalCount > 0
        ? "pending-approval"
        : sessionManagerEnabled
          ? "managed-ready"
          : "local-ready"
      : recentThreadLifecycleActionCount > 0
        ? "history-only"
        : "blocked",
    executionGateEnabled: turnStartEnabled,
    turnStartRoute: turnStartEnabled
      ? sessionManagerEnabled
        ? "session-manager"
        : "local-probe"
      : "blocked",
    turnStartPreflightAvailable: true,
    turnStartPreflightRequired: true,
    approvalPipelineRequired: true,
    denyOnlyDecisionIntakeImplemented: true,
    approvalForwardingEnabled: approvalForwardingGateEnabled,
    approvalAcceptOnceEnabled: approvalAcceptGateEnabled,
    requestScopedApprovalOnly: true,
    sessionWideApprovalDecisionsAccepted: false,
    pendingApprovalCount: safePendingApprovalCount,
    modelTrafficAllowed: turnStartEnabled,
    appServerTrafficAllowed: turnStartEnabled,
    promptForwardingAllowed: turnStartEnabled,
    sessionManagerEnabled,
    persistentSessionRoutingEnabled: Boolean(turnStartEnabled && sessionManagerEnabled),
    targetSelection: "suffix-only",
    sandbox: "read-only",
    approvalPolicy: "on-request",
    threadLifecycleActionHistoryVisible: true,
    recentThreadLifecycleActionCount,
    preflightTokensReturned: false,
    promptsReturned: false,
    fullIdsReturned: false,
    pathsReturned: false,
    decisionTokensReturned: false,
    rawApprovalDetailsReturned: false,
    rawPayloadsReturned: false,
  };
}

function summarizeTurnExecutionAuthority({
  readiness = {},
  options = {},
  pendingApprovalCount = 0,
  threadLifecycleActionHistory = {},
} = {}) {
  const executionGateEnabled = Boolean(readiness.executionGateEnabled);
  const approvalForwardingGateEnabled = isApprovalForwardingGateEnabled(options);
  const approvalAcceptGateEnabled = isApprovalAcceptGateEnabled(options);
  return {
    returned: true,
    state: cleanDisplayText(readiness.state, 80) ?? "blocked",
    authorityMode: executionGateEnabled
      ? approvalAcceptGateEnabled
        ? "model-traffic-with-request-scoped-accept-once"
        : approvalForwardingGateEnabled
          ? "model-traffic-with-managed-deny"
          : "model-traffic-with-local-deny"
      : "blocked",
    executionGateEnabled,
    turnStartRoute: cleanDisplayText(readiness.turnStartRoute, 80) ?? "blocked",
    turnStartPreflightAvailable: true,
    turnStartPreflightRequired: true,
    onePreflightTokenPerTurn: true,
    modelTrafficAllowed: Boolean(readiness.modelTrafficAllowed),
    appServerTrafficAllowed: Boolean(readiness.appServerTrafficAllowed),
    promptForwardingAllowed: Boolean(readiness.promptForwardingAllowed),
    sessionManagerEnabled: Boolean(readiness.sessionManagerEnabled),
    persistentSessionRoutingEnabled: Boolean(readiness.persistentSessionRoutingEnabled),
    pendingApprovalCount: safeCount(pendingApprovalCount),
    threadLifecycleActionHistoryVisible: true,
    recentThreadLifecycleActionCount: safeCount(threadLifecycleActionHistory.count),
    targetSelection: "suffix-only",
    sandbox: "read-only",
    networkAccessAllowed: false,
    approvalPolicy: "on-request",
    approvalPipelineRequired: true,
    denyOnlyDecisionIntakeImplemented: true,
    approvalForwardingEnabled: approvalForwardingGateEnabled,
    approvalAcceptOnceEnabled: approvalAcceptGateEnabled,
    requestScopedApprovalOnly: true,
    sessionWideApprovalDecisionsAccepted: false,
    permissionsGrantForwardingAccepted: false,
    permissionsGrantManagementAccepted: false,
    execPolicyAmendmentsAccepted: false,
    networkAmendmentsAccepted: false,
    persistentRootGrantsAccepted: false,
    browserPromptsAcceptedByGateRead: false,
    browserCwdAccepted: false,
    browserSandboxAccepted: false,
    browserApprovalPolicyAccepted: false,
    browserEnvironmentAccepted: false,
    preflightTokensReturned: false,
    promptsReturned: false,
    fullIdsReturned: false,
    pathsReturned: false,
    decisionTokensReturned: false,
    rawApprovalDetailsReturned: false,
    rawPayloadsReturned: false,
    appServerPayloadReturned: false,
  };
}

export function buildExecutionGate({
  workspace,
  options = {},
  threadLifecycleActionHistory = [],
}) {
  const approvalForwardingGateEnabled = isApprovalForwardingGateEnabled(options);
  const approvalAcceptGateEnabled = isApprovalAcceptGateEnabled(options);
  const turnStartEnabled = Boolean(options.turnStartEnabled);
  const pendingApprovalCount = safeCount(options.pendingApprovalCount);
  const recentThreadLifecycleActionHistory = sanitizeThreadLifecycleActionHistory(
    threadLifecycleActionHistory,
  );
  const turnExecutionReadiness = summarizeTurnExecutionReadiness({
    options,
    pendingApprovalCount,
    threadLifecycleActionHistory: recentThreadLifecycleActionHistory,
  });
  const turnExecutionAuthority = summarizeTurnExecutionAuthority({
    readiness: turnExecutionReadiness,
    options,
    pendingApprovalCount,
    threadLifecycleActionHistory: recentThreadLifecycleActionHistory,
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    gate: {
      state: turnExecutionReadiness.state,
      pendingApprovalCount,
      executionEnabled: turnStartEnabled,
      approvalPipelineImplemented: approvalForwardingGateEnabled,
      approvalDecisionsAccepted: approvalForwardingGateEnabled,
      denyOnlyDecisionIntakeImplemented: true,
      approvalDecisionForwardingImplemented: approvalForwardingGateEnabled,
      acceptOnceApprovalForwardingImplemented: approvalAcceptGateEnabled,
      sessionWideApprovalDecisionsAccepted: false,
      denyOnlyApprovalPolicyImplemented: true,
      threadLifecycleActionHistoryVisible: true,
      recentThreadLifecycleActionCount: recentThreadLifecycleActionHistory.count,
      browserPromptsAccepted: false,
      appServerTrafficAllowed: turnStartEnabled,
    },
    action: {
      type: "turn-start",
      execution: turnStartEnabled ? "enabled" : "blocked",
      modelTraffic: turnStartEnabled,
      sendsPromptToAppServer: turnStartEnabled,
      wouldStartTurn: turnStartEnabled,
      appServerTouched: turnStartEnabled,
      reason: turnStartEnabled ? "turn-start-opt-in-enabled" : "execution-gate-not-implemented",
    },
    turnExecutionReadiness,
    turnExecutionAuthority,
    threadLifecycleActionHistory: recentThreadLifecycleActionHistory,
    policy: {
      approvalPolicy: "on-request",
      sandbox: "read-only",
      requiresExplicitExecutionGate: true,
      requiresApprovalPipeline: true,
      implemented: turnStartEnabled,
      threadLifecycleActionHistoryReturned: true,
      threadLifecycleActionHistoryLimit: MAX_THREAD_LIFECYCLE_ACTION_HISTORY_RECORDS,
      preflightTokensReturned: false,
      promptsReturned: false,
      fullIdsReturned: false,
      pathsReturned: false,
      rawPayloadsReturned: false,
      turnExecutionReadinessReturned: true,
      turnExecutionAuthorityReturned: true,
      turnExecutionAuthorityTokensReturned: false,
      turnExecutionAuthorityPromptsReturned: false,
      turnExecutionAuthorityRawPayloadsReturned: false,
      approvalRequestHandling: {
        browserDecisionsAccepted: approvalForwardingGateEnabled,
        browserDenyOnlyDecisionsRecorded: true,
        forwardedToAppServer: approvalForwardingGateEnabled,
        acceptOnceForwardedToAppServer: approvalAcceptGateEnabled,
        sessionWideApprovalsAccepted: false,
        automaticDenyOnlyResponses: true,
        handledMethods: [
          SERVER_REQUEST_METHODS.commandApproval,
          SERVER_REQUEST_METHODS.fileChangeApproval,
          SERVER_REQUEST_METHODS.legacyExecCommandApproval,
          SERVER_REQUEST_METHODS.legacyApplyPatchApproval,
        ],
        unsupportedMethodsBlockTurnStart: true,
      },
    },
  };
}

