export function buildLiveSessionControlPreflight(
  body,
  { workspace, liveSessionControlEnabled = false, turnSteerEnabled = false },
) {
  const action = validateLiveSessionControlAction(body?.action);
  const threadIdSuffix = validateThreadSuffix(body?.thread);
  const turnIdSuffix = action === "interrupt" || action === "steer"
    ? validateTurnSuffix(body?.turn)
    : validateEmptyTurnSuffix(body?.turn);
  const prompt = action === "steer"
    ? validatePrompt(body?.prompt)
    : validateEmptyLiveSessionPrompt(body?.prompt);
  const method = liveSessionControlMethod(action);
  const executionGateEnabled = action === "steer"
    ? Boolean(turnSteerEnabled)
    : Boolean(liveSessionControlEnabled);

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
    },
    action: {
      type: "live-session-control-preflight",
      liveSessionAction: action,
      method,
      execution: "blocked",
      wouldControlLiveSession: false,
      wouldSendPromptToAppServer: false,
      modelTraffic: false,
      appServerTouched: false,
      reason: action === "steer"
        ? "turn-steer-requires-opt-in"
        : "live-session-control-requires-opt-in",
    },
    liveSessionControl: {
      action,
      method,
      threadIdSuffix,
      turnIdSuffix,
      fullIdsReturned: false,
      promptTextReturned: false,
      threadContentReturned: false,
    },
    prompt: {
      present: prompt !== null,
      charCount: prompt?.length ?? 0,
      lineCount: prompt ? prompt.split(/\r\n|\r|\n/).length : 0,
      textReturned: false,
    },
    policy: {
      readOnly: true,
      appServerTraffic: false,
      modelTraffic: false,
      commandTraffic: false,
      liveSessionMutation: false,
      promptsReturned: false,
      fullIdsReturned: false,
      pathsReturned: false,
      threadContentReturned: false,
      requiresExplicitEnablement: true,
      requiresLiveSessionManager: true,
      executionRouteImplemented: true,
      executionGateEnabled,
      sendsPromptToAppServer: false,
      browserMethodCallsAccepted: false,
      implemented: false,
    },
  };
}

