function sanitizeLiveSessionControlHistory(records) {
  const items = Array.isArray(records)
    ? records.slice(0, MAX_LIVE_SESSION_CONTROL_RECORDS).map((record) =>
        sanitizeLiveSessionControlHistoryRecord(record),
      )
    : [];
  return {
    count: items.length,
    items,
    limit: MAX_LIVE_SESSION_CONTROL_RECORDS,
    fullIdsReturned: false,
    promptsReturned: false,
    pathsReturned: false,
    threadContentReturned: false,
    preflightTokensReturned: false,
  };
}

function buildLiveSessionLifecycle({ liveSessions, recentControls, options = {} }) {
  const loadedThreadCount = safeCount(
    liveSessions?.returnedThreadCount ?? liveSessions?.threadIdSuffixes?.length ?? liveSessions?.count,
  );
  const recentControlCount = safeCount(recentControls?.count);
  const recentControlItems = Array.isArray(recentControls?.items) ? recentControls.items : [];
  const recentInterruptCount = recentControlItems.filter(
    (item) => item?.action?.liveSessionAction === "interrupt",
  ).length;
  const recentUnsubscribeCount = recentControlItems.filter(
    (item) =>
      item?.action?.liveSessionAction === "unsubscribe" &&
      item?.action?.type !== "live-session-bulk-control",
  ).length;
  const recentSteerCount = recentControlItems.filter(
    (item) => item?.action?.liveSessionAction === "steer",
  ).length;
  const recentBulkUnsubscribeCount = recentControlItems.filter(
    (item) => item?.action?.type === "live-session-bulk-control",
  ).length;
  const recentModelTrafficControlCount = recentControlItems.filter((item) =>
    Boolean(item?.action?.modelTraffic),
  ).length;
  const recentFailedControlCount = recentControlItems.filter(isFailedLiveSessionControl).length;
  const latestControl = summarizeLatestLiveSessionControl(recentControlItems[0]);
  const inventoryVisible = liveSessions?.state === "visible";
  const interruptEnabled = Boolean(options.liveSessionControlEnabled);
  const unsubscribeEnabled = Boolean(options.liveSessionControlEnabled);
  const steerEnabled = Boolean(options.turnSteerEnabled);
  const bulkUnsubscribeEnabled = Boolean(
    options.liveSessionBulkControlEnabled && options.sessionManagerEnabled,
  );
  const controlActionsEnabled = [interruptEnabled, unsubscribeEnabled, steerEnabled].filter(Boolean)
    .length;
  const activeSessionOperations = buildActiveSessionOperationsSummary({
    inventoryVisible,
    loadedThreadCount,
    recentControlCount,
    interruptEnabled,
    unsubscribeEnabled,
    steerEnabled,
    bulkUnsubscribeEnabled,
    options,
  });
  const activeSessionManagement = buildActiveSessionManagementSummary({
    inventoryVisible,
    loadedThreadCount,
    recentControlCount,
    latestControl,
    interruptEnabled,
    unsubscribeEnabled,
    steerEnabled,
    bulkUnsubscribeEnabled,
    options,
  });
  const activeSessionReadiness = buildActiveSessionReadinessSummary({
    activeSessionOperations,
    activeSessionManagement,
  });
  const activeSessionRoutingContract = buildActiveSessionRoutingContract({
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
  });
  const activeSessionWorkflowContract = buildActiveSessionWorkflowContract({
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
    activeSessionRoutingContract,
  });
  const activeSessionSafetyContract = buildActiveSessionSafetyContract({
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
    activeSessionRoutingContract,
    activeSessionWorkflowContract,
  });
  const activeSessionAuditContract = buildActiveSessionAuditContract({
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
    activeSessionRoutingContract,
    activeSessionWorkflowContract,
    activeSessionSafetyContract,
    recentInterruptCount,
    recentUnsubscribeCount,
    recentSteerCount,
    recentBulkUnsubscribeCount,
    recentModelTrafficControlCount,
    recentFailedControlCount,
    options,
  });
  const activeSessionInteractionContract = buildActiveSessionInteractionContract({
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
    activeSessionRoutingContract,
    activeSessionWorkflowContract,
    activeSessionSafetyContract,
    activeSessionAuditContract,
  });
  return {
    state: inventoryVisible
      ? loadedThreadCount > 0
        ? "active"
        : recentControlCount > 0
          ? "history-only"
          : "idle"
      : recentControlCount > 0
        ? "history-only"
        : "blocked",
    loadedSessionInventoryVisible: inventoryVisible,
    loadedThreadCount,
    recentControlCount,
    recentInterruptCount,
    recentUnsubscribeCount,
    recentSteerCount,
    recentBulkUnsubscribeCount,
    recentModelTrafficControlCount,
    recentSucceededControlCount: Math.max(0, recentControlCount - recentFailedControlCount),
    recentFailedControlCount,
    latestControl,
    controlPreflightAvailable: true,
    controlActionCount: 3,
    controlActionsEnabled,
    interruptEnabled,
    unsubscribeEnabled,
    steerEnabled,
    bulkControlAvailable: true,
    bulkUnsubscribeEnabled,
    modelTrafficControlEnabled: steerEnabled,
    sessionManagerEnabled: Boolean(options.sessionManagerEnabled),
    sessionManagerBackedControls: Boolean(options.sessionManagerEnabled),
    activeSessionOperations,
    activeSessionManagement,
    activeSessionReadiness,
    activeSessionRoutingContract,
    activeSessionWorkflowContract,
    activeSessionSafetyContract,
    activeSessionAuditContract,
    activeSessionInteractionContract,
    fullIdsReturned: false,
    promptsReturned: false,
    pathsReturned: false,
    threadContentReturned: false,
    preflightTokensReturned: false,
    controlBreakdownReturned: true,
    latestControlReturned: Boolean(latestControl),
    controlPromptTextReturned: false,
    controlPreflightTokensReturned: false,
  };
}

