function sanitizeTerminalControlConfirmationHistoryRecord(record, { recordedAt = null } = {}) {
  const confirmation = record?.confirmation ?? {};
  const source = record?.payload ?? record ?? {};
  const confirmationAction = confirmation.action ?? {};
  const sourceAction = source.action ?? record?.action ?? {};
  const control = source.terminalControl ?? record?.terminalControl ?? {};
  const preflight = confirmation.preflight ?? record?.preflight ?? {};
  const terminalAction = sanitizeTerminalControlActionLabel(
    sourceAction.terminalAction ?? confirmationAction.terminalAction,
    sourceAction.method ?? confirmationAction.method,
  );
  const workspace = confirmation.workspace ?? source.workspace ?? record?.workspace;
  return {
    recordedAt: cleanDisplayText(recordedAt ?? record?.recordedAt, 40),
    workspace: workspace
      ? {
          id: cleanDisplayText(workspace.id, 80),
          label: cleanDisplayText(workspace.label, 120),
          isDefault: Boolean(workspace.isDefault),
        }
      : null,
    action: {
      type: "terminal-control-preflight",
      terminalAction,
      method:
        cleanDisplayText(confirmationAction.method, 100) ??
        cleanDisplayText(sourceAction.method, 100) ??
        terminalControlMethod(terminalAction),
      execution: "blocked",
      preflightConfirmed: true,
      mutationExecuted: false,
      wouldWriteInput: false,
      wouldResize: false,
      wouldTerminate: false,
      terminalSessionTouched: false,
      appServerTouched: false,
    },
    terminalControl: sanitizeTerminalControlHistoryMetadata(control),
    preflight: {
      tokenConsumed: Boolean(preflight.tokenConsumed),
      tokenReturned: false,
      workspaceId: cleanDisplayText(preflight.scope?.workspaceId ?? preflight.workspaceId, 80),
      rawIntentStored: false,
      rawIntentReturned: false,
      intentHashReturned: false,
      oneTimeUseEnforced: preflight.oneTimeUseEnforced !== false,
    },
    policy: {
      ...terminalControlHistoryPolicy(),
      mutationExecuted: false,
    },
  };
}

function sanitizeTerminalControlHistoryMetadata(control) {
  const session = control?.session ?? {};
  const input = control?.input ?? {};
  const resize = control?.resize ?? {};
  const rows = Number.isSafeInteger(resize.rows) ? resize.rows : null;
  const cols = Number.isSafeInteger(resize.cols) ? resize.cols : null;
  return {
    session: {
      selectorCharCount: safeCount(session.selectorCharCount),
      selectorReturned: false,
      fullIdReturned: false,
      suffixReturned: false,
    },
    input: {
      present: Boolean(input.present),
      charCount: safeCount(input.charCount),
      lineCount: safeCount(input.lineCount),
      textReturned: false,
    },
    resize: {
      rows,
      cols,
      dimensionsReturned: Boolean(resize.dimensionsReturned && rows !== null && cols !== null),
    },
  };
}

function terminalControlHistoryPolicy() {
  return {
    readOnly: true,
    appServerTraffic: false,
    modelTraffic: false,
    commandExecution: false,
    terminalSessionsVisible: false,
    terminalWrite: false,
    terminalResize: false,
    terminalTerminate: false,
    terminalSessionTouched: false,
    filesystemWrites: false,
    preflightTokenReturned: false,
    sessionSelectorsReturned: false,
    sessionIdentifiersReturned: false,
    inputTextReturned: false,
    outputTextReturned: false,
    requiresApprovalPipeline: true,
    requiresLiveSessionManager: true,
    browserMethodCallsAccepted: false,
    implemented: false,
  };
}

function sanitizeTerminalControlActionLabel(action, method) {
  const clean = cleanDisplayText(action, 40);
  if (["write", "resize", "terminate"].includes(clean)) {
    return clean;
  }
  switch (method) {
    case "command/exec/write":
    case "process/writeStdin":
      return "write";
    case "command/exec/resize":
    case "process/resizePty":
      return "resize";
    case "command/exec/terminate":
    case "process/kill":
      return "terminate";
    default:
      return "unknown";
  }
}

