function summarizeLatestIntegrationLifecycleAction(payload = {}) {
  const candidates = [
    ...integrationLifecycleHistoryCandidates(payload.preflightConfirmationHistory, "confirmation"),
    ...integrationLifecycleHistoryCandidates(payload.accountLoginHistory, "account-login"),
    ...integrationLifecycleHistoryCandidates(payload.accountCreditsNudgeHistory, "account-credits-nudge"),
    ...integrationLifecycleHistoryCandidates(payload.accountResetCreditHistory, "account-reset-credit"),
    ...integrationLifecycleHistoryCandidates(payload.accountLogoutHistory, "account-logout"),
    ...integrationLifecycleHistoryCandidates(payload.preflightHistory, "preflight"),
  ].sort((a, b) => String(b.recordedAt ?? "").localeCompare(String(a.recordedAt ?? "")));
  const candidate = candidates[0];
  if (!candidate) {
    return null;
  }
  const item = candidate.item;
  const action = item?.action ?? {};
  const result = item?.result ?? {};
  const preflight = item?.preflight ?? {};
  const integrationAction = item?.integrationAction ?? {};
  return {
    source: candidate.source,
    type: cleanDisplayText(action.type, 80) ?? candidate.source,
    method:
      cleanDisplayText(action.method, 100) ??
      cleanDisplayText(integrationAction.method, 100) ??
      "unknown",
    category: cleanDisplayText(action.category ?? integrationAction.category, 80),
    status: cleanDisplayText(result.status ?? action.execution, 80) ?? "recorded",
    appServerTouched: Boolean(action.appServerTouched),
    authMutation: Boolean(action.authMutation),
    authFlowStarted: Boolean(action.authFlowStarted),
    authFlowCanceled: Boolean(action.authFlowCanceled),
    preflightTokenIssued: Boolean(preflight.tokenIssued),
    preflightTokenConsumed: Boolean(preflight.tokenConsumed),
    auditLogged: Boolean(item?.policy?.auditLogWritten),
    modelTraffic: false,
    preflightTokenReturned: false,
    namesReturned: false,
    targetReturned: false,
    argumentTextReturned: false,
    resourceContentReturned: false,
    skillContentsReturned: false,
    urlsReturned: false,
    pathsReturned: false,
    secretsReturned: false,
    rawPayloadReturned: false,
  };
}

function integrationLifecycleHistoryCandidates(history, source) {
  const items = Array.isArray(history?.items) ? history.items : [];
  return items.map((item) => ({
    item,
    source,
    recordedAt: item?.recordedAt,
  }));
}

export function buildTerminalActions({
  workspace,
  options = {},
  terminalCommandHistory = [],
  processSpawnHistory = [],
  threadShellCommandHistory = [],
  terminalControlPreflightHistory = [],
  terminalControlConfirmationHistory = [],
  fileActionHistory = [],
}) {
  const methodAudit = terminalActionMethodAudit();
  const commandHistory = sanitizeTerminalCommandHistory(terminalCommandHistory);
  const recentProcessSpawnHistory = sanitizeProcessSpawnHistory(processSpawnHistory);
  const recentThreadShellCommandHistory =
    sanitizeThreadShellCommandHistory(threadShellCommandHistory);
  const controlPreflightHistory = sanitizeTerminalControlPreflightHistory(
    terminalControlPreflightHistory,
  );
  const controlConfirmationHistory = sanitizeTerminalControlConfirmationHistory(
    terminalControlConfirmationHistory,
  );
  const recentFileActionHistory = sanitizeFileActionHistory(fileActionHistory);
  const terminalBackgroundCleanupEnabled = Boolean(
    options.sessionManagerEnabled && options.terminalCleanEnabled,
  );
  const terminalBackgroundListEnabled = Boolean(
    options.sessionManagerEnabled && options.terminalListEnabled,
  );
  const terminalBackgroundTerminateEnabled = Boolean(
    options.sessionManagerEnabled && options.terminalBackgroundTerminateEnabled,
  );
  const terminalCommandExecutionEnabled = Boolean(
    options.terminalCommandEnabled &&
      sanitizeTerminalCommandAllowlist(options.terminalCommandAllowlist).length > 0,
  );
  const processSpawnExecutionEnabled = Boolean(
    options.processSpawnEnabled &&
      sanitizeTerminalCommandAllowlist(options.processSpawnAllowlist).length > 0,
  );
  const threadShellCommandExecutionEnabled = Boolean(
    options.sessionManagerEnabled &&
      options.threadShellCommandEnabled &&
      sanitizeThreadShellCommandAllowlist(options.threadShellCommandAllowlist).length > 0,
  );
  const terminalControlEnabled = Boolean(
    options.sessionManagerEnabled && options.terminalControlEnabled,
  );
  const processTerminalControlEnabled = Boolean(
    options.sessionManagerEnabled && options.processTerminalControlEnabled,
  );
  const fileActionEnabled = Boolean(options.fileActionEnabled);
  const approvalForwardingGateEnabled = isApprovalForwardingGateEnabled(options);
  const approvalAcceptGateEnabled = isApprovalAcceptGateEnabled(options);
  const hasEnabledLocalActions =
    terminalCommandExecutionEnabled ||
    processSpawnExecutionEnabled ||
    threadShellCommandExecutionEnabled ||
    terminalControlEnabled ||
    processTerminalControlEnabled ||
    terminalBackgroundCleanupEnabled ||
    terminalBackgroundListEnabled ||
    terminalBackgroundTerminateEnabled ||
    fileActionEnabled ||
    approvalForwardingGateEnabled;
  const actionScope = buildTerminalActionScope({
    terminalCommandExecutionEnabled,
    processSpawnExecutionEnabled,
    threadShellCommandExecutionEnabled,
    terminalControlEnabled,
    processTerminalControlEnabled,
    terminalBackgroundCleanupEnabled,
    terminalBackgroundListEnabled,
    terminalBackgroundTerminateEnabled,
    fileActionEnabled,
    approvalForwardingGateEnabled,
    approvalAcceptGateEnabled,
    liveSessionControlEnabled: options.liveSessionControlEnabled,
    turnSteerEnabled: options.turnSteerEnabled,
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspace: publicWorkspaces([workspace])[0],
    appServer: {
      touched: false,
      modelTraffic: false,
      commandTraffic: false,
      auditedMethods: terminalActionMethodNames(),
      blockedMethodCount: methodAudit.length,
    },
    terminal: {
      state:
        terminalBackgroundCleanupEnabled ||
        terminalBackgroundListEnabled ||
        terminalBackgroundTerminateEnabled ||
        terminalControlEnabled ||
        processTerminalControlEnabled ||
        terminalCommandExecutionEnabled ||
        processSpawnExecutionEnabled ||
        threadShellCommandExecutionEnabled
          ? "partial"
          : "blocked",
      sessionsVisible: false,
      lifecycleSnapshotsVisible: true,
      commandHistoryVisible: true,
      recentCommandCount: commandHistory.count,
      processSpawnHistoryVisible: true,
      recentProcessSpawnCount: recentProcessSpawnHistory.count,
      threadShellCommandHistoryVisible: true,
      recentThreadShellCommandCount: recentThreadShellCommandHistory.count,
      controlPreflightHistoryVisible: true,
      recentControlPreflightCount: controlPreflightHistory.count,
      controlConfirmationHistoryVisible: true,
      recentControlConfirmationCount: controlConfirmationHistory.count,
      fileActionHistoryVisible: true,
      recentFileActionCount: recentFileActionHistory.count,
      outputTextReturned: false,
      inputTextReturned: false,
      sessionIdentifiersReturned: false,
      writeEnabled: terminalControlEnabled || processTerminalControlEnabled,
      resizeEnabled: terminalControlEnabled || processTerminalControlEnabled,
      terminateEnabled: terminalControlEnabled || processTerminalControlEnabled,
      commandExecControlEnabled: terminalControlEnabled,
      processControlEnabled: processTerminalControlEnabled,
      backgroundCleanEnabled: terminalBackgroundCleanupEnabled,
      backgroundListEnabled: terminalBackgroundListEnabled,
      backgroundTerminateEnabled: terminalBackgroundTerminateEnabled,
      auditedSessionMethods: methodAudit
        .filter((method) =>
          ["terminal-input", "terminal-control", "host-process", "thread-shell"].includes(
            method.category,
          ),
        )
        .map((method) => method.method),
      reason: terminalBackgroundCleanupEnabled
        ? "background-clean-opt-in-enabled"
        : terminalBackgroundTerminateEnabled
          ? "background-terminate-opt-in-enabled"
        : terminalBackgroundListEnabled
          ? "background-list-opt-in-enabled"
        : terminalControlEnabled
          ? "command-exec-terminal-control-opt-in-enabled"
          : processTerminalControlEnabled
          ? "process-terminal-control-opt-in-enabled"
          : terminalCommandExecutionEnabled
          ? "command-exec-opt-in-enabled"
          : processSpawnExecutionEnabled
            ? "process-spawn-opt-in-enabled"
            : threadShellCommandExecutionEnabled
              ? "thread-shell-command-opt-in-enabled"
              : "terminal-methods-blocked-by-policy",
    },
    actions: {
      state: hasEnabledLocalActions ? "partial" : "blocked",
      commandExecutionEnabled: terminalCommandExecutionEnabled,
      processSpawnEnabled: processSpawnExecutionEnabled,
      threadShellCommandEnabled: threadShellCommandExecutionEnabled,
      fileWriteEnabled: fileActionEnabled,
      approvalDecisionsAccepted: approvalForwardingGateEnabled,
      acceptOnceApprovalDecisionsAccepted: approvalAcceptGateEnabled,
      sessionWideApprovalDecisionsAccepted: false,
      terminalBackgroundCleanupEnabled,
      terminalBackgroundListEnabled,
      terminalBackgroundTerminateEnabled,
      terminalControlEnabled,
      processTerminalControlEnabled,
      terminalCommandHistoryCount: commandHistory.count,
      processSpawnHistoryCount: recentProcessSpawnHistory.count,
      threadShellCommandHistoryCount: recentThreadShellCommandHistory.count,
      fileActionHistoryCount: recentFileActionHistory.count,
      shellAccessEnabled: threadShellCommandExecutionEnabled,
      auditedActionMethods: methodAudit
        .filter((method) =>
          ["sandboxed-command", "thread-shell", "filesystem-write", "turn-control"].includes(
            method.category,
          ),
        )
        .map((method) => method.method),
      reason: hasEnabledLocalActions
        ? "explicit-local-action-gates-enabled"
        : "action-methods-blocked-by-policy",
    },
    actionScope,
    commandHistory,
    processSpawnHistory: recentProcessSpawnHistory,
    threadShellCommandHistory: recentThreadShellCommandHistory,
    terminalControlPreflightHistory: controlPreflightHistory,
    terminalControlConfirmationHistory: controlConfirmationHistory,
    fileActionHistory: recentFileActionHistory,
    methodAudit,
    policy: {
      filesystemReads: false,
      appServerTraffic:
        terminalCommandExecutionEnabled ||
        processSpawnExecutionEnabled ||
        threadShellCommandExecutionEnabled ||
        terminalControlEnabled ||
        processTerminalControlEnabled ||
        terminalBackgroundCleanupEnabled ||
        terminalBackgroundListEnabled ||
        terminalBackgroundTerminateEnabled,
      commandExecution:
        terminalCommandExecutionEnabled ||
        processSpawnExecutionEnabled ||
        threadShellCommandExecutionEnabled,
      hostProcessExecution: processSpawnExecutionEnabled || threadShellCommandExecutionEnabled,
      commandHistoryReturned: true,
      commandHistoryLimit: MAX_TERMINAL_COMMAND_HISTORY_RECORDS,
      processSpawnHistoryReturned: true,
      processSpawnHistoryLimit: MAX_PROCESS_SPAWN_HISTORY_RECORDS,
      threadShellCommandHistoryReturned: true,
      threadShellCommandHistoryLimit: MAX_TERMINAL_COMMAND_HISTORY_RECORDS,
      terminalControlPreflightHistoryReturned: true,
      terminalControlConfirmationHistoryReturned: true,
      terminalControlHistoryLimit: MAX_TERMINAL_CONTROL_HISTORY_RECORDS,
      fileActionHistoryReturned: true,
      fileActionHistoryLimit: MAX_FILE_ACTION_HISTORY_RECORDS,
      commandTextReturned: false,
      argvReturned: false,
      terminalWrite: terminalControlEnabled || processTerminalControlEnabled,
      terminalResize: terminalControlEnabled || processTerminalControlEnabled,
      terminalTerminate: terminalControlEnabled || processTerminalControlEnabled,
      terminalBackgroundCleanup: terminalBackgroundCleanupEnabled,
      terminalBackgroundList: terminalBackgroundListEnabled,
      terminalBackgroundTerminate: terminalBackgroundTerminateEnabled,
      terminalLifecycleSnapshots: true,
      terminalOutputReturned: false,
      terminalSessionIdentifiersReturned: false,
      preflightTokensReturned: false,
      requiresProtocolAudit: false,
      requiresApprovalPipeline: true,
      requiresLiveSessionManager: true,
      requiresCommandAllowlist: true,
      requiresProcessAllowlist: true,
      requiresExactCommandAllowlist: true,
      localFileActions: fileActionEnabled,
      localTerminalCommandExecution: terminalCommandExecutionEnabled,
      localProcessSpawnExecution: processSpawnExecutionEnabled,
      threadShellCommandExecution: threadShellCommandExecutionEnabled,
      unsandboxedThreadShell: threadShellCommandExecutionEnabled,
      commandExecTerminalControl: terminalControlEnabled,
      processTerminalControl: processTerminalControlEnabled,
      backgroundTerminalList: terminalBackgroundListEnabled,
      backgroundTerminalTerminate: terminalBackgroundTerminateEnabled,
      approvalDecisionForwarding: approvalForwardingGateEnabled,
      acceptOnceApprovalDecisionForwarding: approvalAcceptGateEnabled,
      sessionWideApprovalDecisionsAccepted: false,
      browserMethodCallsAccepted: false,
      implemented: hasEnabledLocalActions,
      actionScopeReturned: true,
    },
  };
}

function buildTerminalActionScope({
  terminalCommandExecutionEnabled = false,
  processSpawnExecutionEnabled = false,
  threadShellCommandExecutionEnabled = false,
  terminalControlEnabled = false,
  processTerminalControlEnabled = false,
  terminalBackgroundCleanupEnabled = false,
  terminalBackgroundListEnabled = false,
  terminalBackgroundTerminateEnabled = false,
  fileActionEnabled = false,
  approvalForwardingGateEnabled = false,
  approvalAcceptGateEnabled = false,
  liveSessionControlEnabled = false,
  turnSteerEnabled = false,
} = {}) {
  const enabledActions = [
    terminalCommandExecutionEnabled ? "command/exec" : null,
    processSpawnExecutionEnabled ? "process/spawn" : null,
    threadShellCommandExecutionEnabled ? "thread/shellCommand" : null,
    terminalControlEnabled ? "command/exec terminal-control" : null,
    processTerminalControlEnabled ? "process terminal-control" : null,
    terminalBackgroundCleanupEnabled ? "thread/backgroundTerminals/clean" : null,
    terminalBackgroundListEnabled ? "thread/backgroundTerminals/list" : null,
    terminalBackgroundTerminateEnabled ? "thread/backgroundTerminals/terminate" : null,
    fileActionEnabled ? "local-file-action" : null,
    approvalForwardingGateEnabled ? "approval-decision-forwarding" : null,
    approvalAcceptGateEnabled ? "approval-accept-once" : null,
    liveSessionControlEnabled ? "live-session-interrupt-unsubscribe" : null,
    turnSteerEnabled ? "live-session-steer" : null,
  ].filter(Boolean);
  const blockedHighRiskMethods = [
    ...(processSpawnExecutionEnabled ? [] : ["process/spawn"]),
    ...(processTerminalControlEnabled
      ? []
      : ["process/writeStdin", "process/resizePty", "process/kill"]),
    ...(threadShellCommandExecutionEnabled ? [] : ["thread/shellCommand"]),
    ...(terminalControlEnabled
      ? []
      : [
          "command/exec/write",
          "command/exec/resize",
          "command/exec/terminate",
        ]),
    ...(terminalBackgroundListEnabled ? [] : ["thread/backgroundTerminals/list"]),
    ...(terminalBackgroundTerminateEnabled
      ? []
      : ["thread/backgroundTerminals/terminate"]),
  ];
  return {
    returned: true,
    state: enabledActions.length > 0 ? "partial" : "blocked",
    enabledActionCount: enabledActions.length,
    enabledActions,
    blockedHighRiskMethodCount: blockedHighRiskMethods.length,
    blockedHighRiskMethods,
    commandExecEnabled: Boolean(terminalCommandExecutionEnabled),
    processSpawnEnabled: Boolean(processSpawnExecutionEnabled),
    threadShellEnabled: Boolean(threadShellCommandExecutionEnabled),
    terminalInputEnabled: Boolean(terminalControlEnabled || processTerminalControlEnabled),
    terminalResizeEnabled: Boolean(terminalControlEnabled || processTerminalControlEnabled),
    terminalTerminateEnabled: Boolean(terminalControlEnabled || processTerminalControlEnabled),
    processTerminalControlEnabled: Boolean(processTerminalControlEnabled),
    terminalBackgroundCleanupEnabled: Boolean(terminalBackgroundCleanupEnabled),
    terminalBackgroundListEnabled: Boolean(terminalBackgroundListEnabled),
    terminalBackgroundTerminateEnabled: Boolean(terminalBackgroundTerminateEnabled),
    localFileActionsEnabled: Boolean(fileActionEnabled),
    approvalForwardingEnabled: Boolean(approvalForwardingGateEnabled),
    acceptOnceApprovalForwardingEnabled: Boolean(approvalAcceptGateEnabled),
    liveSessionControlEnabled: Boolean(liveSessionControlEnabled),
    turnSteerEnabled: Boolean(turnSteerEnabled),
    highRiskMethodCallsAccepted: Boolean(
      terminalControlEnabled ||
        processTerminalControlEnabled ||
        processSpawnExecutionEnabled ||
        threadShellCommandExecutionEnabled,
    ),
    requiresLiveSessionOwnership: true,
    requiresApprovalPipeline: true,
    commandTextReturned: false,
    argvReturned: false,
    terminalOutputReturned: false,
    sessionIdentifiersReturned: false,
    pathsReturned: false,
    rawPayloadsReturned: false,
    reason: "high-risk-terminal-methods-require-live-session-ownership-and-approval-provenance",
  };
}

function buildTurnDraftMetadata(body, { workspace }) {
  const prompt = validatePrompt(body?.prompt);
  const threadIdSuffix = validateThreadSuffix(body?.thread);
  return {
    workspace: publicWorkspaces([workspace])[0],
    target: {
      threadIdSuffix,
    },
    prompt: {
      hasContent: true,
      charCount: prompt.length,
      lineCount: prompt.split(/\r\n|\r|\n/).length,
    },
  };
}

