function sanitizeThreadSearchSummary(
  search,
  { searchTerm = "", archived = false, enabled = false, blocked = false } = {},
) {
  const items = Array.isArray(search?.items) ? search.items : [];
  const safeItems = blocked
    ? []
    : items.slice(0, 20).map((item) => ({
        idSuffix: cleanDisplayText(item.idSuffix, 16),
        archived: Boolean(item.archived ?? search?.archivedFilter ?? archived),
        hasSnippet: Boolean(item.hasSnippet),
        hasName: Boolean(item.hasName),
        hasPreview: Boolean(item.hasPreview),
        status: statusLabel(item.status),
        source: cleanDisplayText(item.source, 60),
        modelProvider: cleanDisplayText(item.modelProvider, 80),
        createdAt: safeNumber(item.createdAt),
        updatedAt: safeNumber(item.updatedAt),
        cwdBasename: safeBasename(item.cwdBasename),
        hasGitInfo: Boolean(item.hasGitInfo),
      }));
  return {
    method: "thread/search",
    state: blocked ? "blocked" : "visible",
    enabled: Boolean(enabled),
    searchTermAccepted: !blocked,
    searchTermCharCount: safeCount(search?.searchTermCharCount ?? searchTerm.length),
    searchTermLineCount: safeCount(search?.searchTermLineCount ?? countTextLines(searchTerm)),
    archivedFilter: Boolean(search?.archivedFilter ?? archived),
    count: blocked ? 0 : safeCount(search?.count),
    returnedCount: safeItems.length,
    hasNextCursor: !blocked && Boolean(search?.hasNextCursor),
    hasBackwardsCursor: !blocked && Boolean(search?.hasBackwardsCursor),
    snippetCount: blocked ? 0 : safeCount(search?.snippetCount),
    threadNameCount: blocked ? 0 : safeCount(search?.threadNameCount),
    previewCount: blocked ? 0 : safeCount(search?.previewCount),
    cwdBasenameCount: blocked ? 0 : safeCount(search?.cwdBasenameCount),
    items: safeItems,
    searchTermReturned: false,
    snippetsReturned: false,
    namesReturned: false,
    previewsReturned: false,
    fullIdsReturned: false,
    pathsReturned: false,
    cursorsReturned: false,
    rawPayloadReturned: false,
  };
}

function threadSearchPolicy({ enabled = false } = {}) {
  return {
    readOnly: true,
    appServerTraffic: Boolean(enabled),
    modelTraffic: false,
    commandTraffic: false,
    requiresExplicitEnablement: true,
    executionGateEnabled: Boolean(enabled),
    browserMethodCallsAccepted: Boolean(enabled),
    searchTermReturned: false,
    snippetsReturned: false,
    namesReturned: false,
    previewsReturned: false,
    fullIdsReturned: false,
    pathsReturned: false,
    cursorsReturned: false,
    rawPayloadReturned: false,
    implemented: Boolean(enabled),
  };
}

