    additionalSpeedTierCount: safeCount(models?.additionalSpeedTierCount),
    reasoningEffortOptionCount: safeCount(models?.reasoningEffortOptionCount),
    descriptionCount: safeCount(models?.descriptionCount),
    displayNameCount: safeCount(models?.displayNameCount),
