function sanitizeAppInventoryItems(items) {
  if (!Array.isArray(items)) {
    return [];
  }
  return items.slice(0, MAX_INTEGRATION_DISPLAY_ITEMS).map((item) => {
    const pluginDisplayNames = Array.isArray(item?.pluginDisplayNames)
      ? item.pluginDisplayNames
          .slice(0, MAX_INTEGRATION_DISPLAY_ITEMS)
          .map((name) => sanitizeIntegrationDisplayName(name))
          .filter(Boolean)
      : [];
    return {
      name: sanitizeIntegrationDisplayName(item?.name),
      enabled: Boolean(item?.enabled),
      accessible: Boolean(item?.accessible),
      discoverable: Boolean(item?.discoverable),
      pluginDisplayNameCount: safeCount(item?.pluginDisplayNameCount),
      returnedPluginDisplayNameCount: pluginDisplayNames.length,
      pluginDisplayNames,
    };
  });
}

