function validatePluginReadName(value, label) {
  if (typeof value !== "string") {
    throwRequestError(`${label} name must be a string`, 400);
  }
  const clean = value.trim();
  if (clean.length === 0) {
    throwRequestError(`${label} name is required`, 400);
  }
  if (clean.length > MAX_MCP_REFERENCE_CHARS) {
    throwRequestError(`${label} name must be ${MAX_MCP_REFERENCE_CHARS} characters or fewer`, 400);
  }
  if (clean.includes("\0") || !/^[A-Za-z0-9_.@-]+$/.test(clean)) {
    throwRequestError(`${label} name contains unsupported text`, 400);
  }
  return clean;
}

function parsePluginSkillReadArguments(value) {
  const parsed = parseStrictPluginContentArguments(value, "Plugin skill read arguments");
  const allowedKeys = new Set(["remoteMarketplaceName", "skillName"]);
  for (const key of Object.keys(parsed)) {
    if (!allowedKeys.has(key)) {
      throwRequestError("Plugin skill read arguments contain unsupported keys", 400);
    }
  }
  return {
    remoteMarketplaceName: validatePluginReadName(
      parsed.remoteMarketplaceName,
      "Remote marketplace",
    ),
    skillName: validatePluginReadName(parsed.skillName, "Skill"),
  };
}

function parsePluginShareListArguments(value) {
  const parsed = parseStrictPluginContentArguments(value, "Plugin share-list arguments", {
    allowEmpty: true,
  });
  if (Object.keys(parsed).length > 0) {
    throwRequestError("Plugin share-list arguments must be empty", 400);
  }
  return {};
}

function parseStrictPluginContentArguments(value, label, { allowEmpty = false } = {}) {
  const raw = value == null ? "" : typeof value === "string" ? value : JSON.stringify(value);
  if (typeof raw !== "string") {
    throwRequestError(`${label} must be a JSON object`, 400);
  }
  if (raw.length > MAX_MCP_ARGUMENT_CHARS) {
    throwRequestError(`${label} must be ${MAX_MCP_ARGUMENT_CHARS} characters or fewer`, 400);
  }
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    if (allowEmpty) {
      return {};
    }
    throwRequestError(`${label} are required`, 400);
  }
  let parsed = null;
  try {
    parsed = JSON.parse(trimmed);
  } catch {
    throwRequestError(`${label} must be valid JSON`, 400);
  }
  if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) {
    throwRequestError(`${label} must be a JSON object`, 400);
  }
  return parsed;
}

function parsePluginReadArguments(value) {
  const raw = value == null ? "" : typeof value === "string" ? value : JSON.stringify(value);
  if (typeof raw !== "string") {
    throwRequestError("Plugin read arguments must be a JSON object", 400);
  }
  if (raw.length > MAX_MCP_ARGUMENT_CHARS) {
    throwRequestError(`Plugin read arguments must be ${MAX_MCP_ARGUMENT_CHARS} characters or fewer`, 400);
  }
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    return { remoteMarketplaceName: null };
  }
  let parsed = null;
  try {
    parsed = JSON.parse(trimmed);
  } catch {
    throwRequestError("Plugin read arguments must be valid JSON", 400);
  }
  if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) {
    throwRequestError("Plugin read arguments must be a JSON object", 400);
  }
  const allowedKeys = new Set(["remoteMarketplaceName", "marketplacePath"]);
  for (const key of Object.keys(parsed)) {
    if (!allowedKeys.has(key)) {
      throwRequestError("Plugin read arguments contain unsupported keys", 400);
    }
  }
  if (parsed.marketplacePath != null) {
    throwRequestError("Plugin read marketplace paths are not supported", 400);
  }
  if (parsed.remoteMarketplaceName == null || parsed.remoteMarketplaceName === "") {
    return { remoteMarketplaceName: null };
  }
  return {
    remoteMarketplaceName: validatePluginReadName(parsed.remoteMarketplaceName, "Remote marketplace"),
  };
}

function validateActionPreflightType(value) {
  const actionType = cleanDisplayText(value, 80);
  if (!Object.hasOwn(ACTION_PREFLIGHT_CONFIRMATION_FIELD_CONTRACTS, actionType)) {
    throwRequestError("Action preflight type is unsupported", 400);
  }
  return actionType;
}

function validateActionPreflightToken(value) {
  if (typeof value !== "string" || !/^preflight-[A-Za-z0-9_-]{16,128}$/.test(value)) {
    throwRequestError("Action preflight token is required", 400);
  }
  return value;
}

function validateAccountLoginRef(value) {
  const clean = safeAccountLoginRef(value);
  if (!clean) {
    throwRequestError("Account login flow selector is required", 400);
  }
  return clean;
}

function sanitizeAccountCreditsNudgeCreditType(value) {
  const clean = cleanDisplayText(value, 16);
  if (clean === "credits" || clean === "usage_limit") {
    return clean;
  }
  throwRequestError("Unsupported account credits nudge type", 400);
}

function sanitizeAccountCreditsNudgeStatus(value) {
  const clean = cleanDisplayText(value, 32);
  if (clean === "sent" || clean === "cooldown_active") {
    return clean;
  }
  return "unknown";
}

function sanitizeAccountResetCreditOutcome(value) {
  const clean = cleanDisplayText(value, 32);
  return ["reset", "nothingToReset", "noCredit", "alreadyRedeemed"].includes(clean)
    ? clean
    : "unknown";
}

function buildPrivateResetCreditIdempotencyKey(consumedPreflight) {
  const workspacePart = cleanDisplayText(consumedPreflight?.scope?.workspaceId, 32) ?? "workspace";
  return `codex-app-port-${workspacePart}-${randomBytes(16).toString("hex")}`;
}

function validateTerminalRef(value) {
  const clean = safeTerminalRef(value);
  if (!clean) {
    throwRequestError("Background terminal selector is required", 400);
  }
  return clean;
}

function validateRemoteClientRef(value) {
  const clean = safeRemoteClientRef(value);
  if (!clean) {
    throwRequestError("Remote client selector is required", 400);
  }
  return clean;
}

function validateActionPreflightConfirmationFields(body) {
  const actionType = validateActionPreflightType(body?.actionType);
  rejectUnknownBodyFields(body, ACTION_PREFLIGHT_CONFIRMATION_FIELD_CONTRACTS[actionType]);
  validateBrowserPostBodyFieldPolicies(
    body,
    BROWSER_POST_BODY_CONTRACTS["/api/action-preflight-confirm"],
  );
}

function stripActionPreflightControlFields(body) {
  if (!body || typeof body !== "object" || Array.isArray(body)) {
    throwRequestError("Action preflight confirmation body must be an object", 400);
  }
  const actionBody = {};
  for (const [key, value] of Object.entries(body)) {
    if (!["actionType", "preflightToken"].includes(key)) {
      actionBody[key] = value;
    }
  }
  return actionBody;
}

function fileActionMethod(action) {
  switch (action) {
    case "writeFile":
      return "fs/writeFile";
    case "remove":
      return "fs/remove";
    case "copy":
      return "fs/copy";
    case "createDirectory":
      return "fs/createDirectory";
    default:
      return "unknown";
  }
}

function throwRequestError(message, statusCode) {
  const error = new Error(message);
  error.statusCode = statusCode;
  throw error;
}

function contentTypeFor(pathname) {
  switch (extname(pathname)) {
    case ".html":
      return "text/html; charset=utf-8";
    case ".css":
      return "text/css; charset=utf-8";
    case ".js":
      return "text/javascript; charset=utf-8";
    default:
      return "application/octet-stream";
  }
}
